BLOCKS = [
    ('new', '<p>Construct cid from byte array</p>\n'),
    ('is_ascii', '<p>Checks if all bytes in this slice are within the ASCII range.</p>\n<p>An empty slice returns <code>true</code>.</p>\n'),
    ('as_ascii_unchecked', '<p>Converts this slice of bytes into a slice of ASCII characters,\nwithout checking whether they’re valid.</p>\n<h5 id="safety"><a class="doc-anchor" href="#safety">§</a>Safety</h5>\n<p>Every byte in the slice must be in <code>0..=127</code>, or else this is UB.</p>\n'),
    ('eq_ignore_ascii_case', '<p>Checks that two slices are an ASCII case-insensitive match.</p>\n<p>Same as <code>to_ascii_lowercase(a) == to_ascii_lowercase(b)</code>,\nbut without allocating and copying temporaries.</p>\n'),
    ('make_ascii_uppercase', '<p>Converts this slice to its ASCII upper case equivalent in-place.</p>\n<p>ASCII letters ‘a’ to ‘z’ are mapped to ‘A’ to ‘Z’,\nbut non-ASCII letters are unchanged.</p>\n<p>To return a new uppercased value without modifying the existing one, use\n<a href="#method.to_ascii_uppercase"><code>to_ascii_uppercase</code></a>.</p>\n'),
    ('make_ascii_lowercase', '<p>Converts this slice to its ASCII lower case equivalent in-place.</p>\n<p>ASCII letters ‘A’ to ‘Z’ are mapped to ‘a’ to ‘z’,\nbut non-ASCII letters are unchanged.</p>\n<p>To return a new lowercased value without modifying the existing one, use\n<a href="#method.to_ascii_lowercase"><code>to_ascii_lowercase</code></a>.</p>\n'),
    ('escape_ascii', '<p>Returns an iterator that produces an escaped version of this slice,\ntreating it as an ASCII string.</p>\n<h5 id="examples"><a class="doc-anchor" href="#examples">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>s = <span class="string">b"0\\t\\r\\n\'\\"\\\\\\x9d"</span>;\n<span class="kw">let </span>escaped = s.escape_ascii().to_string();\n<span class="macro">assert_eq!</span>(escaped, <span class="string">"0\\\\t\\\\r\\\\n\\\\\'\\\\\\"\\\\\\\\\\\\x9d"</span>);</code></pre>'),
    ('trim_ascii_start', '<p>Returns a byte slice with leading ASCII whitespace bytes removed.</p>\n<p>‘Whitespace’ refers to the definition used by\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.u8.html#method.is_ascii_whitespace" title="method u8::is_ascii_whitespace"><code>u8::is_ascii_whitespace</code></a>.</p>\n<h5 id="examples-1"><a class="doc-anchor" href="#examples-1">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="macro">assert_eq!</span>(<span class="string">b" \\t hello world\\n"</span>.trim_ascii_start(), <span class="string">b"hello world\\n"</span>);\n<span class="macro">assert_eq!</span>(<span class="string">b"  "</span>.trim_ascii_start(), <span class="string">b""</span>);\n<span class="macro">assert_eq!</span>(<span class="string">b""</span>.trim_ascii_start(), <span class="string">b""</span>);</code></pre>'),
    ('trim_ascii_end', '<p>Returns a byte slice with trailing ASCII whitespace bytes removed.</p>\n<p>‘Whitespace’ refers to the definition used by\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.u8.html#method.is_ascii_whitespace" title="method u8::is_ascii_whitespace"><code>u8::is_ascii_whitespace</code></a>.</p>\n<h5 id="examples-2"><a class="doc-anchor" href="#examples-2">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="macro">assert_eq!</span>(<span class="string">b"\\r hello world\\n "</span>.trim_ascii_end(), <span class="string">b"\\r hello world"</span>);\n<span class="macro">assert_eq!</span>(<span class="string">b"  "</span>.trim_ascii_end(), <span class="string">b""</span>);\n<span class="macro">assert_eq!</span>(<span class="string">b""</span>.trim_ascii_end(), <span class="string">b""</span>);</code></pre>'),
    ('trim_ascii', '<p>Returns a byte slice with leading and trailing ASCII whitespace bytes\nremoved.</p>\n<p>‘Whitespace’ refers to the definition used by\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.u8.html#method.is_ascii_whitespace" title="method u8::is_ascii_whitespace"><code>u8::is_ascii_whitespace</code></a>.</p>\n<h5 id="examples-3"><a class="doc-anchor" href="#examples-3">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="macro">assert_eq!</span>(<span class="string">b"\\r hello world\\n "</span>.trim_ascii(), <span class="string">b"hello world"</span>);\n<span class="macro">assert_eq!</span>(<span class="string">b"  "</span>.trim_ascii(), <span class="string">b""</span>);\n<span class="macro">assert_eq!</span>(<span class="string">b""</span>.trim_ascii(), <span class="string">b""</span>);</code></pre>'),
    ('len', '<p>Returns the number of elements in the slice.</p>\n<h5 id="examples-4"><a class="doc-anchor" href="#examples-4">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>a = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>];\n<span class="macro">assert_eq!</span>(a.len(), <span class="number">3</span>);</code></pre>'),
    ('get', '<p>Returns a reference to an element or subslice depending on the type of\nindex.</p>\n<ul>\n<li>If given a position, returns a reference to the element at that\nposition or <code>None</code> if out of bounds.</li>\n<li>If given a range, returns the subslice corresponding to that range,\nor <code>None</code> if out of bounds.</li>\n</ul>\n<h5 id="examples-22"><a class="doc-anchor" href="#examples-22">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = [<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>];\n<span class="macro">assert_eq!</span>(<span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span><span class="number">40</span>), v.get(<span class="number">1</span>));\n<span class="macro">assert_eq!</span>(<span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>][..]), v.get(<span class="number">0</span>..<span class="number">2</span>));\n<span class="macro">assert_eq!</span>(<span class="prelude-val">None</span>, v.get(<span class="number">3</span>));\n<span class="macro">assert_eq!</span>(<span class="prelude-val">None</span>, v.get(<span class="number">0</span>..<span class="number">4</span>));</code></pre>'),
    ('get_unchecked', '<p>Returns a reference to an element or subslice, without doing bounds\nchecking.</p>\n<p>For a safe alternative see <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.get" title="method slice::get"><code>get</code></a>.</p>\n<h5 id="safety-1"><a class="doc-anchor" href="#safety-1">§</a>Safety</h5>\n<p>Calling this method with an out-of-bounds index is <em><a href="https://doc.rust-lang.org/reference/behavior-considered-undefined.html">undefined behavior</a></em>\neven if the resulting reference is not used.</p>\n<p>You can think of this like <code>.get(index).unwrap_unchecked()</code>.  It’s UB\nto call <code>.get_unchecked(len)</code>, even if you immediately convert to a\npointer.  And it’s UB to call <code>.get_unchecked(..len + 1)</code>,\n<code>.get_unchecked(..=len)</code>, or similar.</p>\n<h5 id="examples-24"><a class="doc-anchor" href="#examples-24">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>x = <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>];\n\n<span class="kw">unsafe </span>{\n    <span class="macro">assert_eq!</span>(x.get_unchecked(<span class="number">1</span>), <span class="kw-2">&amp;</span><span class="number">2</span>);\n}</code></pre>'),
    ('get_unchecked_mut', '<p>Returns a mutable reference to an element or subslice, without doing\nbounds checking.</p>\n<p>For a safe alternative see <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.get_mut" title="method slice::get_mut"><code>get_mut</code></a>.</p>\n<h5 id="safety-2"><a class="doc-anchor" href="#safety-2">§</a>Safety</h5>\n<p>Calling this method with an out-of-bounds index is <em><a href="https://doc.rust-lang.org/reference/behavior-considered-undefined.html">undefined behavior</a></em>\neven if the resulting reference is not used.</p>\n<p>You can think of this like <code>.get_mut(index).unwrap_unchecked()</code>.  It’s\nUB to call <code>.get_unchecked_mut(len)</code>, even if you immediately convert\nto a pointer.  And it’s UB to call <code>.get_unchecked_mut(..len + 1)</code>,\n<code>.get_unchecked_mut(..=len)</code>, or similar.</p>\n<h5 id="examples-25"><a class="doc-anchor" href="#examples-25">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>x = <span class="kw-2">&amp;mut </span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>];\n\n<span class="kw">unsafe </span>{\n    <span class="kw">let </span>elem = x.get_unchecked_mut(<span class="number">1</span>);\n    <span class="kw-2">*</span>elem = <span class="number">13</span>;\n}\n<span class="macro">assert_eq!</span>(x, <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">13</span>, <span class="number">4</span>]);</code></pre>'),
    ('as_ptr', '<p>Returns a raw pointer to the slice’s buffer.</p>\n<p>The caller must ensure that the slice outlives the pointer this\nfunction returns, or else it will end up dangling.</p>\n<p>The caller must also ensure that the memory the pointer (non-transitively) points to\nis never written to (except inside an <code>UnsafeCell</code>) using this pointer or any pointer\nderived from it. If you need to mutate the contents of the slice, use <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_mut_ptr" title="method slice::as_mut_ptr"><code>as_mut_ptr</code></a>.</p>\n<p>Modifying the container referenced by this slice may cause its buffer\nto be reallocated, which would also make any pointers to it invalid.</p>\n<h5 id="examples-26"><a class="doc-anchor" href="#examples-26">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>x = <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>];\n<span class="kw">let </span>x_ptr = x.as_ptr();\n\n<span class="kw">unsafe </span>{\n    <span class="kw">for </span>i <span class="kw">in </span><span class="number">0</span>..x.len() {\n        <span class="macro">assert_eq!</span>(x.get_unchecked(i), <span class="kw-2">&amp;*</span>x_ptr.add(i));\n    }\n}</code></pre>'),
    ('as_mut_ptr', '<p>Returns an unsafe mutable pointer to the slice’s buffer.</p>\n<p>The caller must ensure that the slice outlives the pointer this\nfunction returns, or else it will end up dangling.</p>\n<p>Modifying the container referenced by this slice may cause its buffer\nto be reallocated, which would also make any pointers to it invalid.</p>\n<h5 id="examples-27"><a class="doc-anchor" href="#examples-27">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>x = <span class="kw-2">&amp;mut </span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>];\n<span class="kw">let </span>x_ptr = x.as_mut_ptr();\n\n<span class="kw">unsafe </span>{\n    <span class="kw">for </span>i <span class="kw">in </span><span class="number">0</span>..x.len() {\n        <span class="kw-2">*</span>x_ptr.add(i) += <span class="number">2</span>;\n    }\n}\n<span class="macro">assert_eq!</span>(x, <span class="kw-2">&amp;</span>[<span class="number">3</span>, <span class="number">4</span>, <span class="number">6</span>]);</code></pre>'),
    ('as_ptr_range', '<p>Returns the two raw pointers spanning the slice.</p>\n<p>The returned range is half-open, which means that the end pointer\npoints <em>one past</em> the last element of the slice. This way, an empty\nslice is represented by two equal pointers, and the difference between\nthe two pointers represents the size of the slice.</p>\n<p>See <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_ptr" title="method slice::as_ptr"><code>as_ptr</code></a> for warnings on using these pointers. The end pointer\nrequires extra caution, as it does not point to a valid element in the\nslice.</p>\n<p>This function is useful for interacting with foreign interfaces which\nuse two pointers to refer to a range of elements in memory, as is\ncommon in C++.</p>\n<p>It can also be useful to check if a pointer to an element refers to an\nelement of this slice:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>a = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>];\n<span class="kw">let </span>x = <span class="kw-2">&amp;</span>a[<span class="number">1</span>] <span class="kw">as </span><span class="kw-2">*const </span><span class="kw">_</span>;\n<span class="kw">let </span>y = <span class="kw-2">&amp;</span><span class="number">5 </span><span class="kw">as </span><span class="kw-2">*const </span><span class="kw">_</span>;\n\n<span class="macro">assert!</span>(a.as_ptr_range().contains(<span class="kw-2">&amp;</span>x));\n<span class="macro">assert!</span>(!a.as_ptr_range().contains(<span class="kw-2">&amp;</span>y));</code></pre>'),
    ('as_mut_ptr_range', '<p>Returns the two unsafe mutable pointers spanning the slice.</p>\n<p>The returned range is half-open, which means that the end pointer\npoints <em>one past</em> the last element of the slice. This way, an empty\nslice is represented by two equal pointers, and the difference between\nthe two pointers represents the size of the slice.</p>\n<p>See <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_mut_ptr" title="method slice::as_mut_ptr"><code>as_mut_ptr</code></a> for warnings on using these pointers. The end\npointer requires extra caution, as it does not point to a valid element\nin the slice.</p>\n<p>This function is useful for interacting with foreign interfaces which\nuse two pointers to refer to a range of elements in memory, as is\ncommon in C++.</p>\n'),
    ('as_array', '<p>Gets a reference to the underlying array.</p>\n<p>If <code>N</code> is not exactly equal to the length of <code>self</code>, then this method returns <code>None</code>.</p>\n'),
    ('as_mut_array', '<p>Gets a mutable reference to the slice’s underlying array.</p>\n<p>If <code>N</code> is not exactly equal to the length of <code>self</code>, then this method returns <code>None</code>.</p>\n'),
    ('swap', '<p>Swaps two elements in the slice.</p>\n<p>If <code>a</code> equals to <code>b</code>, it’s guaranteed that elements won’t change value.</p>\n<h5 id="arguments"><a class="doc-anchor" href="#arguments">§</a>Arguments</h5>\n<ul>\n<li>a - The index of the first element</li>\n<li>b - The index of the second element</li>\n</ul>\n<h5 id="panics"><a class="doc-anchor" href="#panics">§</a>Panics</h5>\n<p>Panics if <code>a</code> or <code>b</code> are out of bounds.</p>\n<h5 id="examples-28"><a class="doc-anchor" href="#examples-28">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="string">"a"</span>, <span class="string">"b"</span>, <span class="string">"c"</span>, <span class="string">"d"</span>, <span class="string">"e"</span>];\nv.swap(<span class="number">2</span>, <span class="number">4</span>);\n<span class="macro">assert!</span>(v == [<span class="string">"a"</span>, <span class="string">"b"</span>, <span class="string">"e"</span>, <span class="string">"d"</span>, <span class="string">"c"</span>]);</code></pre>'),
    ('swap_unchecked', '<p>Swaps two elements in the slice, without doing bounds checking.</p>\n<p>For a safe alternative see <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.swap" title="method slice::swap"><code>swap</code></a>.</p>\n<h5 id="arguments-1"><a class="doc-anchor" href="#arguments-1">§</a>Arguments</h5>\n<ul>\n<li>a - The index of the first element</li>\n<li>b - The index of the second element</li>\n</ul>\n<h5 id="safety-3"><a class="doc-anchor" href="#safety-3">§</a>Safety</h5>\n<p>Calling this method with an out-of-bounds index is <em><a href="https://doc.rust-lang.org/reference/behavior-considered-undefined.html">undefined behavior</a></em>.\nThe caller has to ensure that <code>a &lt; self.len()</code> and <code>b &lt; self.len()</code>.</p>\n<h5 id="examples-29"><a class="doc-anchor" href="#examples-29">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(slice_swap_unchecked)]\n\n</span><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="string">"a"</span>, <span class="string">"b"</span>, <span class="string">"c"</span>, <span class="string">"d"</span>];\n<span class="comment">// SAFETY: we know that 1 and 3 are both indices of the slice\n</span><span class="kw">unsafe </span>{ v.swap_unchecked(<span class="number">1</span>, <span class="number">3</span>) };\n<span class="macro">assert!</span>(v == [<span class="string">"a"</span>, <span class="string">"d"</span>, <span class="string">"c"</span>, <span class="string">"b"</span>]);</code></pre>'),
    ('reverse', '<p>Reverses the order of elements in the slice, in place.</p>\n<h5 id="examples-30"><a class="doc-anchor" href="#examples-30">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>];\nv.reverse();\n<span class="macro">assert!</span>(v == [<span class="number">3</span>, <span class="number">2</span>, <span class="number">1</span>]);</code></pre>'),
    ('iter', '<p>Returns an iterator over the slice.</p>\n<p>The iterator yields all items from start to end.</p>\n<h5 id="examples-31"><a class="doc-anchor" href="#examples-31">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>x = <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>];\n<span class="kw">let </span><span class="kw-2">mut </span>iterator = x.iter();\n\n<span class="macro">assert_eq!</span>(iterator.next(), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span><span class="number">1</span>));\n<span class="macro">assert_eq!</span>(iterator.next(), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span><span class="number">2</span>));\n<span class="macro">assert_eq!</span>(iterator.next(), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span><span class="number">4</span>));\n<span class="macro">assert_eq!</span>(iterator.next(), <span class="prelude-val">None</span>);</code></pre>'),
    ('iter_mut', '<p>Returns an iterator that allows modifying each value.</p>\n<p>The iterator yields all items from start to end.</p>\n<h5 id="examples-32"><a class="doc-anchor" href="#examples-32">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>x = <span class="kw-2">&amp;mut </span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>];\n<span class="kw">for </span>elem <span class="kw">in </span>x.iter_mut() {\n    <span class="kw-2">*</span>elem += <span class="number">2</span>;\n}\n<span class="macro">assert_eq!</span>(x, <span class="kw-2">&amp;</span>[<span class="number">3</span>, <span class="number">4</span>, <span class="number">6</span>]);</code></pre>'),
    ('as_chunks_unchecked', '<p>Splits the slice into a slice of <code>N</code>-element arrays,\nassuming that there’s no remainder.</p>\n<p>This is the inverse operation to <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_flattened" title="method slice::as_flattened"><code>as_flattened</code></a>.</p>\n<p>As this is <code>unsafe</code>, consider whether you could use <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_chunks" title="method slice::as_chunks"><code>as_chunks</code></a> or\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_rchunks" title="method slice::as_rchunks"><code>as_rchunks</code></a> instead, perhaps via something like\n<code>if let (chunks, []) = slice.as_chunks()</code> or\n<code>let (chunks, []) = slice.as_chunks() else { unreachable!() };</code>.</p>\n<h5 id="safety-4"><a class="doc-anchor" href="#safety-4">§</a>Safety</h5>\n<p>This may only be called when</p>\n<ul>\n<li>The slice splits exactly into <code>N</code>-element chunks (aka <code>self.len() % N == 0</code>).</li>\n<li><code>N != 0</code>.</li>\n</ul>\n<h5 id="examples-38"><a class="doc-anchor" href="#examples-38">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>slice: <span class="kw-2">&amp;</span>[char] = <span class="kw-2">&amp;</span>[<span class="string">\'l\'</span>, <span class="string">\'o\'</span>, <span class="string">\'r\'</span>, <span class="string">\'e\'</span>, <span class="string">\'m\'</span>, <span class="string">\'!\'</span>];\n<span class="kw">let </span>chunks: <span class="kw-2">&amp;</span>[[char; <span class="number">1</span>]] =\n    <span class="comment">// SAFETY: 1-element chunks never have remainder\n    </span><span class="kw">unsafe </span>{ slice.as_chunks_unchecked() };\n<span class="macro">assert_eq!</span>(chunks, <span class="kw-2">&amp;</span>[[<span class="string">\'l\'</span>], [<span class="string">\'o\'</span>], [<span class="string">\'r\'</span>], [<span class="string">\'e\'</span>], [<span class="string">\'m\'</span>], [<span class="string">\'!\'</span>]]);\n<span class="kw">let </span>chunks: <span class="kw-2">&amp;</span>[[char; <span class="number">3</span>]] =\n    <span class="comment">// SAFETY: The slice length (6) is a multiple of 3\n    </span><span class="kw">unsafe </span>{ slice.as_chunks_unchecked() };\n<span class="macro">assert_eq!</span>(chunks, <span class="kw-2">&amp;</span>[[<span class="string">\'l\'</span>, <span class="string">\'o\'</span>, <span class="string">\'r\'</span>], [<span class="string">\'e\'</span>, <span class="string">\'m\'</span>, <span class="string">\'!\'</span>]]);\n\n<span class="comment">// These would be unsound:\n// let chunks: &amp;[[_; 5]] = slice.as_chunks_unchecked() // The slice length is not a multiple of 5\n// let chunks: &amp;[[_; 0]] = slice.as_chunks_unchecked() // Zero-length chunks are never allowed</span></code></pre>'),
    ('as_chunks', '<p>Splits the slice into a slice of <code>N</code>-element arrays,\nstarting at the beginning of the slice,\nand a remainder slice with length strictly less than <code>N</code>.</p>\n<p>The remainder is meaningful in the division sense.  Given\n<code>let (chunks, remainder) = slice.as_chunks()</code>, then:</p>\n<ul>\n<li><code>chunks.len()</code> equals <code>slice.len() / N</code>,</li>\n<li><code>remainder.len()</code> equals <code>slice.len() % N</code>, and</li>\n<li><code>slice.len()</code> equals <code>chunks.len() * N + remainder.len()</code>.</li>\n</ul>\n<p>You can flatten the chunks back into a slice-of-<code>T</code> with <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_flattened" title="method slice::as_flattened"><code>as_flattened</code></a>.</p>\n<h5 id="panics-6"><a class="doc-anchor" href="#panics-6">§</a>Panics</h5>\n<p>Panics if <code>N</code> is zero.</p>\n<p>Note that this check is against a const generic parameter, not a runtime\nvalue, and thus a particular monomorphization will either always panic\nor it will never panic.</p>\n<h5 id="examples-39"><a class="doc-anchor" href="#examples-39">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>slice = [<span class="string">\'l\'</span>, <span class="string">\'o\'</span>, <span class="string">\'r\'</span>, <span class="string">\'e\'</span>, <span class="string">\'m\'</span>];\n<span class="kw">let </span>(chunks, remainder) = slice.as_chunks();\n<span class="macro">assert_eq!</span>(chunks, <span class="kw-2">&amp;</span>[[<span class="string">\'l\'</span>, <span class="string">\'o\'</span>], [<span class="string">\'r\'</span>, <span class="string">\'e\'</span>]]);\n<span class="macro">assert_eq!</span>(remainder, <span class="kw-2">&amp;</span>[<span class="string">\'m\'</span>]);</code></pre>'),
    ('as_rchunks', '<p>Splits the slice into a slice of <code>N</code>-element arrays,\nstarting at the end of the slice,\nand a remainder slice with length strictly less than <code>N</code>.</p>\n<p>The remainder is meaningful in the division sense.  Given\n<code>let (remainder, chunks) = slice.as_rchunks()</code>, then:</p>\n<ul>\n<li><code>remainder.len()</code> equals <code>slice.len() % N</code>,</li>\n<li><code>chunks.len()</code> equals <code>slice.len() / N</code>, and</li>\n<li><code>slice.len()</code> equals <code>chunks.len() * N + remainder.len()</code>.</li>\n</ul>\n<p>You can flatten the chunks back into a slice-of-<code>T</code> with <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_flattened" title="method slice::as_flattened"><code>as_flattened</code></a>.</p>\n<h5 id="panics-7"><a class="doc-anchor" href="#panics-7">§</a>Panics</h5>\n<p>Panics if <code>N</code> is zero.</p>\n<p>Note that this check is against a const generic parameter, not a runtime\nvalue, and thus a particular monomorphization will either always panic\nor it will never panic.</p>\n<h5 id="examples-40"><a class="doc-anchor" href="#examples-40">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>slice = [<span class="string">\'l\'</span>, <span class="string">\'o\'</span>, <span class="string">\'r\'</span>, <span class="string">\'e\'</span>, <span class="string">\'m\'</span>];\n<span class="kw">let </span>(remainder, chunks) = slice.as_rchunks();\n<span class="macro">assert_eq!</span>(remainder, <span class="kw-2">&amp;</span>[<span class="string">\'l\'</span>]);\n<span class="macro">assert_eq!</span>(chunks, <span class="kw-2">&amp;</span>[[<span class="string">\'o\'</span>, <span class="string">\'r\'</span>], [<span class="string">\'e\'</span>, <span class="string">\'m\'</span>]]);</code></pre>'),
    ('as_chunks_unchecked_mut', '<p>Splits the slice into a slice of <code>N</code>-element arrays,\nassuming that there’s no remainder.</p>\n<p>This is the inverse operation to <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_flattened_mut" title="method slice::as_flattened_mut"><code>as_flattened_mut</code></a>.</p>\n<p>As this is <code>unsafe</code>, consider whether you could use <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_chunks_mut" title="method slice::as_chunks_mut"><code>as_chunks_mut</code></a> or\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_rchunks_mut" title="method slice::as_rchunks_mut"><code>as_rchunks_mut</code></a> instead, perhaps via something like\n<code>if let (chunks, []) = slice.as_chunks_mut()</code> or\n<code>let (chunks, []) = slice.as_chunks_mut() else { unreachable!() };</code>.</p>\n<h5 id="safety-5"><a class="doc-anchor" href="#safety-5">§</a>Safety</h5>\n<p>This may only be called when</p>\n<ul>\n<li>The slice splits exactly into <code>N</code>-element chunks (aka <code>self.len() % N == 0</code>).</li>\n<li><code>N != 0</code>.</li>\n</ul>\n<h5 id="examples-41"><a class="doc-anchor" href="#examples-41">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>slice: <span class="kw-2">&amp;mut </span>[char] = <span class="kw-2">&amp;mut </span>[<span class="string">\'l\'</span>, <span class="string">\'o\'</span>, <span class="string">\'r\'</span>, <span class="string">\'e\'</span>, <span class="string">\'m\'</span>, <span class="string">\'!\'</span>];\n<span class="kw">let </span>chunks: <span class="kw-2">&amp;mut </span>[[char; <span class="number">1</span>]] =\n    <span class="comment">// SAFETY: 1-element chunks never have remainder\n    </span><span class="kw">unsafe </span>{ slice.as_chunks_unchecked_mut() };\nchunks[<span class="number">0</span>] = [<span class="string">\'L\'</span>];\n<span class="macro">assert_eq!</span>(chunks, <span class="kw-2">&amp;</span>[[<span class="string">\'L\'</span>], [<span class="string">\'o\'</span>], [<span class="string">\'r\'</span>], [<span class="string">\'e\'</span>], [<span class="string">\'m\'</span>], [<span class="string">\'!\'</span>]]);\n<span class="kw">let </span>chunks: <span class="kw-2">&amp;mut </span>[[char; <span class="number">3</span>]] =\n    <span class="comment">// SAFETY: The slice length (6) is a multiple of 3\n    </span><span class="kw">unsafe </span>{ slice.as_chunks_unchecked_mut() };\nchunks[<span class="number">1</span>] = [<span class="string">\'a\'</span>, <span class="string">\'x\'</span>, <span class="string">\'?\'</span>];\n<span class="macro">assert_eq!</span>(slice, <span class="kw-2">&amp;</span>[<span class="string">\'L\'</span>, <span class="string">\'o\'</span>, <span class="string">\'r\'</span>, <span class="string">\'a\'</span>, <span class="string">\'x\'</span>, <span class="string">\'?\'</span>]);\n\n<span class="comment">// These would be unsound:\n// let chunks: &amp;[[_; 5]] = slice.as_chunks_unchecked_mut() // The slice length is not a multiple of 5\n// let chunks: &amp;[[_; 0]] = slice.as_chunks_unchecked_mut() // Zero-length chunks are never allowed</span></code></pre>'),
    ('as_chunks_mut', '<p>Splits the slice into a slice of <code>N</code>-element arrays,\nstarting at the beginning of the slice,\nand a remainder slice with length strictly less than <code>N</code>.</p>\n<p>The remainder is meaningful in the division sense.  Given\n<code>let (chunks, remainder) = slice.as_chunks_mut()</code>, then:</p>\n<ul>\n<li><code>chunks.len()</code> equals <code>slice.len() / N</code>,</li>\n<li><code>remainder.len()</code> equals <code>slice.len() % N</code>, and</li>\n<li><code>slice.len()</code> equals <code>chunks.len() * N + remainder.len()</code>.</li>\n</ul>\n<p>You can flatten the chunks back into a slice-of-<code>T</code> with <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_flattened_mut" title="method slice::as_flattened_mut"><code>as_flattened_mut</code></a>.</p>\n<h5 id="panics-8"><a class="doc-anchor" href="#panics-8">§</a>Panics</h5>\n<p>Panics if <code>N</code> is zero.</p>\n<p>Note that this check is against a const generic parameter, not a runtime\nvalue, and thus a particular monomorphization will either always panic\nor it will never panic.</p>\n<h5 id="examples-42"><a class="doc-anchor" href="#examples-42">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = <span class="kw-2">&amp;mut </span>[<span class="number">0</span>, <span class="number">0</span>, <span class="number">0</span>, <span class="number">0</span>, <span class="number">0</span>];\n<span class="kw">let </span><span class="kw-2">mut </span>count = <span class="number">1</span>;\n\n<span class="kw">let </span>(chunks, remainder) = v.as_chunks_mut();\nremainder[<span class="number">0</span>] = <span class="number">9</span>;\n<span class="kw">for </span>chunk <span class="kw">in </span>chunks {\n    <span class="kw-2">*</span>chunk = [count; <span class="number">2</span>];\n    count += <span class="number">1</span>;\n}\n<span class="macro">assert_eq!</span>(v, <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">2</span>, <span class="number">9</span>]);</code></pre>'),
    ('as_rchunks_mut', '<p>Splits the slice into a slice of <code>N</code>-element arrays,\nstarting at the end of the slice,\nand a remainder slice with length strictly less than <code>N</code>.</p>\n<p>The remainder is meaningful in the division sense.  Given\n<code>let (remainder, chunks) = slice.as_rchunks_mut()</code>, then:</p>\n<ul>\n<li><code>remainder.len()</code> equals <code>slice.len() % N</code>,</li>\n<li><code>chunks.len()</code> equals <code>slice.len() / N</code>, and</li>\n<li><code>slice.len()</code> equals <code>chunks.len() * N + remainder.len()</code>.</li>\n</ul>\n<p>You can flatten the chunks back into a slice-of-<code>T</code> with <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_flattened_mut" title="method slice::as_flattened_mut"><code>as_flattened_mut</code></a>.</p>\n<h5 id="panics-9"><a class="doc-anchor" href="#panics-9">§</a>Panics</h5>\n<p>Panics if <code>N</code> is zero.</p>\n<p>Note that this check is against a const generic parameter, not a runtime\nvalue, and thus a particular monomorphization will either always panic\nor it will never panic.</p>\n<h5 id="examples-43"><a class="doc-anchor" href="#examples-43">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = <span class="kw-2">&amp;mut </span>[<span class="number">0</span>, <span class="number">0</span>, <span class="number">0</span>, <span class="number">0</span>, <span class="number">0</span>];\n<span class="kw">let </span><span class="kw-2">mut </span>count = <span class="number">1</span>;\n\n<span class="kw">let </span>(remainder, chunks) = v.as_rchunks_mut();\nremainder[<span class="number">0</span>] = <span class="number">9</span>;\n<span class="kw">for </span>chunk <span class="kw">in </span>chunks {\n    <span class="kw-2">*</span>chunk = [count; <span class="number">2</span>];\n    count += <span class="number">1</span>;\n}\n<span class="macro">assert_eq!</span>(v, <span class="kw-2">&amp;</span>[<span class="number">9</span>, <span class="number">1</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">2</span>]);</code></pre>'),
    ('array_windows', '<p>Returns an iterator over overlapping windows of <code>N</code> elements of a slice,\nstarting at the beginning of the slice.</p>\n<p>This is the const generic equivalent of <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.windows" title="method slice::windows"><code>windows</code></a>.</p>\n<p>If <code>N</code> is greater than the size of the slice, it will return no windows.</p>\n<h5 id="panics-10"><a class="doc-anchor" href="#panics-10">§</a>Panics</h5>\n<p>Panics if <code>N</code> is zero.</p>\n<p>Note that this check is against a const generic parameter, not a runtime\nvalue, and thus a particular monomorphization will either always panic\nor it will never panic.</p>\n<h5 id="examples-44"><a class="doc-anchor" href="#examples-44">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>slice = [<span class="number">0</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>];\n<span class="kw">let </span><span class="kw-2">mut </span>iter = slice.array_windows();\n<span class="macro">assert_eq!</span>(iter.next().unwrap(), <span class="kw-2">&amp;</span>[<span class="number">0</span>, <span class="number">1</span>]);\n<span class="macro">assert_eq!</span>(iter.next().unwrap(), <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">2</span>]);\n<span class="macro">assert_eq!</span>(iter.next().unwrap(), <span class="kw-2">&amp;</span>[<span class="number">2</span>, <span class="number">3</span>]);\n<span class="macro">assert!</span>(iter.next().is_none());</code></pre>'),
    ('chunk_by', '<p>Returns an iterator over the slice producing non-overlapping runs\nof elements using the predicate to separate them.</p>\n<p>The predicate is called for every pair of consecutive elements,\nmeaning that it is called on <code>slice[0]</code> and <code>slice[1]</code>,\nfollowed by <code>slice[1]</code> and <code>slice[2]</code>, and so on.</p>\n<h5 id="examples-49"><a class="doc-anchor" href="#examples-49">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>slice = <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">1</span>, <span class="number">1</span>, <span class="number">3</span>, <span class="number">3</span>, <span class="number">2</span>, <span class="number">2</span>, <span class="number">2</span>];\n\n<span class="kw">let </span><span class="kw-2">mut </span>iter = slice.chunk_by(|a, b| a == b);\n\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">1</span>, <span class="number">1</span>][..]));\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">3</span>, <span class="number">3</span>][..]));\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">2</span>, <span class="number">2</span>, <span class="number">2</span>][..]));\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">None</span>);</code></pre>'),
    ('chunk_by_mut', '<p>Returns an iterator over the slice producing non-overlapping mutable\nruns of elements using the predicate to separate them.</p>\n<p>The predicate is called for every pair of consecutive elements,\nmeaning that it is called on <code>slice[0]</code> and <code>slice[1]</code>,\nfollowed by <code>slice[1]</code> and <code>slice[2]</code>, and so on.</p>\n<h5 id="examples-50"><a class="doc-anchor" href="#examples-50">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>slice = <span class="kw-2">&amp;mut </span>[<span class="number">1</span>, <span class="number">1</span>, <span class="number">1</span>, <span class="number">3</span>, <span class="number">3</span>, <span class="number">2</span>, <span class="number">2</span>, <span class="number">2</span>];\n\n<span class="kw">let </span><span class="kw-2">mut </span>iter = slice.chunk_by_mut(|a, b| a == b);\n\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;mut </span>[<span class="number">1</span>, <span class="number">1</span>, <span class="number">1</span>][..]));\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;mut </span>[<span class="number">3</span>, <span class="number">3</span>][..]));\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;mut </span>[<span class="number">2</span>, <span class="number">2</span>, <span class="number">2</span>][..]));\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">None</span>);</code></pre>'),
    ('split_at', '<p>Divides one slice into two at an index.</p>\n<p>The first will contain all indices from <code>[0, mid)</code> (excluding\nthe index <code>mid</code> itself) and the second will contain all\nindices from <code>[mid, len)</code> (excluding the index <code>len</code> itself).</p>\n<h5 id="panics-15"><a class="doc-anchor" href="#panics-15">§</a>Panics</h5>\n<p>Panics if <code>mid &gt; len</code>.  For a non-panicking alternative see\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.split_at_checked" title="method slice::split_at_checked"><code>split_at_checked</code></a>.</p>\n<h5 id="examples-51"><a class="doc-anchor" href="#examples-51">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = [<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>];\n\n{\n   <span class="kw">let </span>(left, right) = v.split_at(<span class="number">0</span>);\n   <span class="macro">assert_eq!</span>(left, []);\n   <span class="macro">assert_eq!</span>(right, [<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>]);\n}\n\n{\n    <span class="kw">let </span>(left, right) = v.split_at(<span class="number">2</span>);\n    <span class="macro">assert_eq!</span>(left, [<span class="string">\'a\'</span>, <span class="string">\'b\'</span>]);\n    <span class="macro">assert_eq!</span>(right, [<span class="string">\'c\'</span>]);\n}\n\n{\n    <span class="kw">let </span>(left, right) = v.split_at(<span class="number">3</span>);\n    <span class="macro">assert_eq!</span>(left, [<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>]);\n    <span class="macro">assert_eq!</span>(right, []);\n}</code></pre>'),
    ('split_at_mut', '<p>Divides one mutable slice into two at an index.</p>\n<p>The first will contain all indices from <code>[0, mid)</code> (excluding\nthe index <code>mid</code> itself) and the second will contain all\nindices from <code>[mid, len)</code> (excluding the index <code>len</code> itself).</p>\n<h5 id="panics-16"><a class="doc-anchor" href="#panics-16">§</a>Panics</h5>\n<p>Panics if <code>mid &gt; len</code>.  For a non-panicking alternative see\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.split_at_mut_checked" title="method slice::split_at_mut_checked"><code>split_at_mut_checked</code></a>.</p>\n<h5 id="examples-52"><a class="doc-anchor" href="#examples-52">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">1</span>, <span class="number">0</span>, <span class="number">3</span>, <span class="number">0</span>, <span class="number">5</span>, <span class="number">6</span>];\n<span class="kw">let </span>(left, right) = v.split_at_mut(<span class="number">2</span>);\n<span class="macro">assert_eq!</span>(left, [<span class="number">1</span>, <span class="number">0</span>]);\n<span class="macro">assert_eq!</span>(right, [<span class="number">3</span>, <span class="number">0</span>, <span class="number">5</span>, <span class="number">6</span>]);\nleft[<span class="number">1</span>] = <span class="number">2</span>;\nright[<span class="number">1</span>] = <span class="number">4</span>;\n<span class="macro">assert_eq!</span>(v, [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">4</span>, <span class="number">5</span>, <span class="number">6</span>]);</code></pre>'),
    ('split_at_unchecked', '<p>Divides one slice into two at an index, without doing bounds checking.</p>\n<p>The first will contain all indices from <code>[0, mid)</code> (excluding\nthe index <code>mid</code> itself) and the second will contain all\nindices from <code>[mid, len)</code> (excluding the index <code>len</code> itself).</p>\n<p>For a safe alternative see <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.split_at" title="method slice::split_at"><code>split_at</code></a>.</p>\n<h5 id="safety-6"><a class="doc-anchor" href="#safety-6">§</a>Safety</h5>\n<p>Calling this method with an out-of-bounds index is <em><a href="https://doc.rust-lang.org/reference/behavior-considered-undefined.html">undefined behavior</a></em>\neven if the resulting reference is not used. The caller has to ensure that\n<code>0 &lt;= mid &lt;= self.len()</code>.</p>\n<h5 id="examples-53"><a class="doc-anchor" href="#examples-53">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = [<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>];\n\n<span class="kw">unsafe </span>{\n   <span class="kw">let </span>(left, right) = v.split_at_unchecked(<span class="number">0</span>);\n   <span class="macro">assert_eq!</span>(left, []);\n   <span class="macro">assert_eq!</span>(right, [<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>]);\n}\n\n<span class="kw">unsafe </span>{\n    <span class="kw">let </span>(left, right) = v.split_at_unchecked(<span class="number">2</span>);\n    <span class="macro">assert_eq!</span>(left, [<span class="string">\'a\'</span>, <span class="string">\'b\'</span>]);\n    <span class="macro">assert_eq!</span>(right, [<span class="string">\'c\'</span>]);\n}\n\n<span class="kw">unsafe </span>{\n    <span class="kw">let </span>(left, right) = v.split_at_unchecked(<span class="number">3</span>);\n    <span class="macro">assert_eq!</span>(left, [<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>]);\n    <span class="macro">assert_eq!</span>(right, []);\n}</code></pre>'),
    ('split_at_mut_unchecked', '<p>Divides one mutable slice into two at an index, without doing bounds checking.</p>\n<p>The first will contain all indices from <code>[0, mid)</code> (excluding\nthe index <code>mid</code> itself) and the second will contain all\nindices from <code>[mid, len)</code> (excluding the index <code>len</code> itself).</p>\n<p>For a safe alternative see <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.split_at_mut" title="method slice::split_at_mut"><code>split_at_mut</code></a>.</p>\n<h5 id="safety-7"><a class="doc-anchor" href="#safety-7">§</a>Safety</h5>\n<p>Calling this method with an out-of-bounds index is <em><a href="https://doc.rust-lang.org/reference/behavior-considered-undefined.html">undefined behavior</a></em>\neven if the resulting reference is not used. The caller has to ensure that\n<code>0 &lt;= mid &lt;= self.len()</code>.</p>\n<h5 id="examples-54"><a class="doc-anchor" href="#examples-54">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">1</span>, <span class="number">0</span>, <span class="number">3</span>, <span class="number">0</span>, <span class="number">5</span>, <span class="number">6</span>];\n<span class="comment">// scoped to restrict the lifetime of the borrows\n</span><span class="kw">unsafe </span>{\n    <span class="kw">let </span>(left, right) = v.split_at_mut_unchecked(<span class="number">2</span>);\n    <span class="macro">assert_eq!</span>(left, [<span class="number">1</span>, <span class="number">0</span>]);\n    <span class="macro">assert_eq!</span>(right, [<span class="number">3</span>, <span class="number">0</span>, <span class="number">5</span>, <span class="number">6</span>]);\n    left[<span class="number">1</span>] = <span class="number">2</span>;\n    right[<span class="number">1</span>] = <span class="number">4</span>;\n}\n<span class="macro">assert_eq!</span>(v, [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">4</span>, <span class="number">5</span>, <span class="number">6</span>]);</code></pre>'),
    ('splitn', '<p>Returns an iterator over subslices separated by elements that match\n<code>pred</code>, limited to returning at most <code>n</code> items. The matched element is\nnot contained in the subslices.</p>\n<p>The last element returned, if any, will contain the remainder of the\nslice.</p>\n<h5 id="examples-63"><a class="doc-anchor" href="#examples-63">§</a>Examples</h5>\n<p>Print the slice split once by numbers divisible by 3 (i.e., <code>[10, 40]</code>,\n<code>[20, 60, 50]</code>):</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = [<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>, <span class="number">20</span>, <span class="number">60</span>, <span class="number">50</span>];\n\n<span class="kw">for </span>group <span class="kw">in </span>v.splitn(<span class="number">2</span>, |num| <span class="kw-2">*</span>num % <span class="number">3 </span>== <span class="number">0</span>) {\n    <span class="macro">println!</span>(<span class="string">"{group:?}"</span>);\n}</code></pre>'),
    ('splitn_mut', '<p>Returns an iterator over mutable subslices separated by elements that match\n<code>pred</code>, limited to returning at most <code>n</code> items. The matched element is\nnot contained in the subslices.</p>\n<p>The last element returned, if any, will contain the remainder of the\nslice.</p>\n<h5 id="examples-64"><a class="doc-anchor" href="#examples-64">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>, <span class="number">20</span>, <span class="number">60</span>, <span class="number">50</span>];\n\n<span class="kw">for </span>group <span class="kw">in </span>v.splitn_mut(<span class="number">2</span>, |num| <span class="kw-2">*</span>num % <span class="number">3 </span>== <span class="number">0</span>) {\n    group[<span class="number">0</span>] = <span class="number">1</span>;\n}\n<span class="macro">assert_eq!</span>(v, [<span class="number">1</span>, <span class="number">40</span>, <span class="number">30</span>, <span class="number">1</span>, <span class="number">60</span>, <span class="number">50</span>]);</code></pre>'),
    ('rsplitn', '<p>Returns an iterator over subslices separated by elements that match\n<code>pred</code> limited to returning at most <code>n</code> items. This starts at the end of\nthe slice and works backwards. The matched element is not contained in\nthe subslices.</p>\n<p>The last element returned, if any, will contain the remainder of the\nslice.</p>\n<h5 id="examples-65"><a class="doc-anchor" href="#examples-65">§</a>Examples</h5>\n<p>Print the slice split once, starting from the end, by numbers divisible\nby 3 (i.e., <code>[50]</code>, <code>[10, 40, 30, 20]</code>):</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = [<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>, <span class="number">20</span>, <span class="number">60</span>, <span class="number">50</span>];\n\n<span class="kw">for </span>group <span class="kw">in </span>v.rsplitn(<span class="number">2</span>, |num| <span class="kw-2">*</span>num % <span class="number">3 </span>== <span class="number">0</span>) {\n    <span class="macro">println!</span>(<span class="string">"{group:?}"</span>);\n}</code></pre>'),
    ('rsplitn_mut', '<p>Returns an iterator over subslices separated by elements that match\n<code>pred</code> limited to returning at most <code>n</code> items. This starts at the end of\nthe slice and works backwards. The matched element is not contained in\nthe subslices.</p>\n<p>The last element returned, if any, will contain the remainder of the\nslice.</p>\n<h5 id="examples-66"><a class="doc-anchor" href="#examples-66">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>s = [<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>, <span class="number">20</span>, <span class="number">60</span>, <span class="number">50</span>];\n\n<span class="kw">for </span>group <span class="kw">in </span>s.rsplitn_mut(<span class="number">2</span>, |num| <span class="kw-2">*</span>num % <span class="number">3 </span>== <span class="number">0</span>) {\n    group[<span class="number">0</span>] = <span class="number">1</span>;\n}\n<span class="macro">assert_eq!</span>(s, [<span class="number">1</span>, <span class="number">40</span>, <span class="number">30</span>, <span class="number">20</span>, <span class="number">60</span>, <span class="number">1</span>]);</code></pre>'),
    ('split_once', '<p>Splits the slice on the first element that matches the specified\npredicate.</p>\n<p>If any matching elements are present in the slice, returns the prefix\nbefore the match and suffix after. The matching element itself is not\nincluded. If no elements match, returns <code>None</code>.</p>\n<h5 id="examples-67"><a class="doc-anchor" href="#examples-67">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(slice_split_once)]\n</span><span class="kw">let </span>s = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">2</span>, <span class="number">4</span>];\n<span class="macro">assert_eq!</span>(s.split_once(|<span class="kw-2">&amp;</span>x| x == <span class="number">2</span>), <span class="prelude-val">Some</span>((\n    <span class="kw-2">&amp;</span>[<span class="number">1</span>][..],\n    <span class="kw-2">&amp;</span>[<span class="number">3</span>, <span class="number">2</span>, <span class="number">4</span>][..]\n)));\n<span class="macro">assert_eq!</span>(s.split_once(|<span class="kw-2">&amp;</span>x| x == <span class="number">0</span>), <span class="prelude-val">None</span>);</code></pre>'),
    ('rsplit_once', '<p>Splits the slice on the last element that matches the specified\npredicate.</p>\n<p>If any matching elements are present in the slice, returns the prefix\nbefore the match and suffix after. The matching element itself is not\nincluded. If no elements match, returns <code>None</code>.</p>\n<h5 id="examples-68"><a class="doc-anchor" href="#examples-68">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(slice_split_once)]\n</span><span class="kw">let </span>s = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">2</span>, <span class="number">4</span>];\n<span class="macro">assert_eq!</span>(s.rsplit_once(|<span class="kw-2">&amp;</span>x| x == <span class="number">2</span>), <span class="prelude-val">Some</span>((\n    <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>][..],\n    <span class="kw-2">&amp;</span>[<span class="number">4</span>][..]\n)));\n<span class="macro">assert_eq!</span>(s.rsplit_once(|<span class="kw-2">&amp;</span>x| x == <span class="number">0</span>), <span class="prelude-val">None</span>);</code></pre>'),
    ('strip_prefix', '<p>Returns a subslice with the prefix removed.</p>\n<p>If the slice starts with <code>prefix</code>, returns the subslice after the prefix, wrapped in <code>Some</code>.\nIf <code>prefix</code> is empty, simply returns the original slice. If <code>prefix</code> is equal to the\noriginal slice, returns an empty slice.</p>\n<p>If the slice does not start with <code>prefix</code>, returns <code>None</code>.</p>\n<h5 id="examples-72"><a class="doc-anchor" href="#examples-72">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>];\n<span class="macro">assert_eq!</span>(v.strip_prefix(<span class="kw-2">&amp;</span>[<span class="number">10</span>]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">40</span>, <span class="number">30</span>][..]));\n<span class="macro">assert_eq!</span>(v.strip_prefix(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">30</span>][..]));\n<span class="macro">assert_eq!</span>(v.strip_prefix(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[][..]));\n<span class="macro">assert_eq!</span>(v.strip_prefix(<span class="kw-2">&amp;</span>[<span class="number">50</span>]), <span class="prelude-val">None</span>);\n<span class="macro">assert_eq!</span>(v.strip_prefix(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">50</span>]), <span class="prelude-val">None</span>);\n\n<span class="kw">let </span>prefix : <span class="kw-2">&amp;</span>str = <span class="string">"he"</span>;\n<span class="macro">assert_eq!</span>(<span class="string">b"hello"</span>.strip_prefix(prefix.as_bytes()),\n           <span class="prelude-val">Some</span>(<span class="string">b"llo"</span>.as_ref()));</code></pre>'),
    ('strip_suffix', '<p>Returns a subslice with the suffix removed.</p>\n<p>If the slice ends with <code>suffix</code>, returns the subslice before the suffix, wrapped in <code>Some</code>.\nIf <code>suffix</code> is empty, simply returns the original slice. If <code>suffix</code> is equal to the\noriginal slice, returns an empty slice.</p>\n<p>If the slice does not end with <code>suffix</code>, returns <code>None</code>.</p>\n<h5 id="examples-73"><a class="doc-anchor" href="#examples-73">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>];\n<span class="macro">assert_eq!</span>(v.strip_suffix(<span class="kw-2">&amp;</span>[<span class="number">30</span>]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>][..]));\n<span class="macro">assert_eq!</span>(v.strip_suffix(<span class="kw-2">&amp;</span>[<span class="number">40</span>, <span class="number">30</span>]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">10</span>][..]));\n<span class="macro">assert_eq!</span>(v.strip_suffix(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[][..]));\n<span class="macro">assert_eq!</span>(v.strip_suffix(<span class="kw-2">&amp;</span>[<span class="number">50</span>]), <span class="prelude-val">None</span>);\n<span class="macro">assert_eq!</span>(v.strip_suffix(<span class="kw-2">&amp;</span>[<span class="number">50</span>, <span class="number">30</span>]), <span class="prelude-val">None</span>);</code></pre>'),
    ('strip_circumfix', '<p>Returns a subslice with the prefix and suffix removed.</p>\n<p>If the slice starts with <code>prefix</code> and ends with <code>suffix</code>, returns the subslice after the\nprefix and before the suffix, wrapped in <code>Some</code>.</p>\n<p>If the slice does not start with <code>prefix</code> or does not end with <code>suffix</code>, returns <code>None</code>.</p>\n<h5 id="examples-74"><a class="doc-anchor" href="#examples-74">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(strip_circumfix)]\n\n</span><span class="kw">let </span>v = <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">50</span>, <span class="number">40</span>, <span class="number">30</span>];\n<span class="macro">assert_eq!</span>(v.strip_circumfix(<span class="kw-2">&amp;</span>[<span class="number">10</span>], <span class="kw-2">&amp;</span>[<span class="number">30</span>]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">50</span>, <span class="number">40</span>][..]));\n<span class="macro">assert_eq!</span>(v.strip_circumfix(<span class="kw-2">&amp;</span>[<span class="number">10</span>], <span class="kw-2">&amp;</span>[<span class="number">40</span>, <span class="number">30</span>]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">50</span>][..]));\n<span class="macro">assert_eq!</span>(v.strip_circumfix(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">50</span>], <span class="kw-2">&amp;</span>[<span class="number">40</span>, <span class="number">30</span>]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[][..]));\n<span class="macro">assert_eq!</span>(v.strip_circumfix(<span class="kw-2">&amp;</span>[<span class="number">50</span>], <span class="kw-2">&amp;</span>[<span class="number">30</span>]), <span class="prelude-val">None</span>);\n<span class="macro">assert_eq!</span>(v.strip_circumfix(<span class="kw-2">&amp;</span>[<span class="number">10</span>], <span class="kw-2">&amp;</span>[<span class="number">40</span>]), <span class="prelude-val">None</span>);\n<span class="macro">assert_eq!</span>(v.strip_circumfix(<span class="kw-2">&amp;</span>[], <span class="kw-2">&amp;</span>[<span class="number">40</span>, <span class="number">30</span>]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">50</span>][..]));\n<span class="macro">assert_eq!</span>(v.strip_circumfix(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">50</span>], <span class="kw-2">&amp;</span>[]), <span class="prelude-val">Some</span>(<span class="kw-2">&amp;</span>[<span class="number">40</span>, <span class="number">30</span>][..]));</code></pre>'),
    ('trim_prefix', '<p>Returns a subslice with the optional prefix removed.</p>\n<p>If the slice starts with <code>prefix</code>, returns the subslice after the prefix.  If <code>prefix</code>\nis empty or the slice does not start with <code>prefix</code>, simply returns the original slice.\nIf <code>prefix</code> is equal to the original slice, returns an empty slice.</p>\n<h5 id="examples-75"><a class="doc-anchor" href="#examples-75">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(trim_prefix_suffix)]\n\n</span><span class="kw">let </span>v = <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>];\n\n<span class="comment">// Prefix present - removes it\n</span><span class="macro">assert_eq!</span>(v.trim_prefix(<span class="kw-2">&amp;</span>[<span class="number">10</span>]), <span class="kw-2">&amp;</span>[<span class="number">40</span>, <span class="number">30</span>][..]);\n<span class="macro">assert_eq!</span>(v.trim_prefix(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>]), <span class="kw-2">&amp;</span>[<span class="number">30</span>][..]);\n<span class="macro">assert_eq!</span>(v.trim_prefix(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>]), <span class="kw-2">&amp;</span>[][..]);\n\n<span class="comment">// Prefix absent - returns original slice\n</span><span class="macro">assert_eq!</span>(v.trim_prefix(<span class="kw-2">&amp;</span>[<span class="number">50</span>]), <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>][..]);\n<span class="macro">assert_eq!</span>(v.trim_prefix(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">50</span>]), <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>][..]);\n\n<span class="kw">let </span>prefix : <span class="kw-2">&amp;</span>str = <span class="string">"he"</span>;\n<span class="macro">assert_eq!</span>(<span class="string">b"hello"</span>.trim_prefix(prefix.as_bytes()), <span class="string">b"llo"</span>.as_ref());</code></pre>'),
    ('trim_suffix', '<p>Returns a subslice with the optional suffix removed.</p>\n<p>If the slice ends with <code>suffix</code>, returns the subslice before the suffix.  If <code>suffix</code>\nis empty or the slice does not end with <code>suffix</code>, simply returns the original slice.\nIf <code>suffix</code> is equal to the original slice, returns an empty slice.</p>\n<h5 id="examples-76"><a class="doc-anchor" href="#examples-76">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(trim_prefix_suffix)]\n\n</span><span class="kw">let </span>v = <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>];\n\n<span class="comment">// Suffix present - removes it\n</span><span class="macro">assert_eq!</span>(v.trim_suffix(<span class="kw-2">&amp;</span>[<span class="number">30</span>]), <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>][..]);\n<span class="macro">assert_eq!</span>(v.trim_suffix(<span class="kw-2">&amp;</span>[<span class="number">40</span>, <span class="number">30</span>]), <span class="kw-2">&amp;</span>[<span class="number">10</span>][..]);\n<span class="macro">assert_eq!</span>(v.trim_suffix(<span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>]), <span class="kw-2">&amp;</span>[][..]);\n\n<span class="comment">// Suffix absent - returns original slice\n</span><span class="macro">assert_eq!</span>(v.trim_suffix(<span class="kw-2">&amp;</span>[<span class="number">50</span>]), <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>][..]);\n<span class="macro">assert_eq!</span>(v.trim_suffix(<span class="kw-2">&amp;</span>[<span class="number">50</span>, <span class="number">30</span>]), <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">40</span>, <span class="number">30</span>][..]);</code></pre>'),
    ('binary_search', '<p>Binary searches this slice for a given element.\nIf the slice is not sorted, the returned result is unspecified and\nmeaningless.</p>\n<p>If the value is found then <a href="https://doc.rust-lang.org/1.95.0/core/result/enum.Result.html#variant.Ok" title="variant core::result::Result::Ok"><code>Result::Ok</code></a> is returned, containing the\nindex of the matching element. If there are multiple matches, then any\none of the matches could be returned. The index is chosen\ndeterministically, but is subject to change in future versions of Rust.\nIf the value is not found then <a href="https://doc.rust-lang.org/1.95.0/core/result/enum.Result.html#variant.Err" title="variant core::result::Result::Err"><code>Result::Err</code></a> is returned, containing\nthe index where a matching element could be inserted while maintaining\nsorted order.</p>\n<p>See also <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.binary_search_by" title="method slice::binary_search_by"><code>binary_search_by</code></a>, <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.binary_search_by_key" title="method slice::binary_search_by_key"><code>binary_search_by_key</code></a>, and <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.partition_point" title="method slice::partition_point"><code>partition_point</code></a>.</p>\n<h5 id="examples-77"><a class="doc-anchor" href="#examples-77">§</a>Examples</h5>\n<p>Looks up a series of four elements. The first is found, with a\nuniquely determined position; the second and third are not\nfound; the fourth could match any position in <code>[1, 4]</code>.</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>s = [<span class="number">0</span>, <span class="number">1</span>, <span class="number">1</span>, <span class="number">1</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">5</span>, <span class="number">8</span>, <span class="number">13</span>, <span class="number">21</span>, <span class="number">34</span>, <span class="number">55</span>];\n\n<span class="macro">assert_eq!</span>(s.binary_search(<span class="kw-2">&amp;</span><span class="number">13</span>),  <span class="prelude-val">Ok</span>(<span class="number">9</span>));\n<span class="macro">assert_eq!</span>(s.binary_search(<span class="kw-2">&amp;</span><span class="number">4</span>),   <span class="prelude-val">Err</span>(<span class="number">7</span>));\n<span class="macro">assert_eq!</span>(s.binary_search(<span class="kw-2">&amp;</span><span class="number">100</span>), <span class="prelude-val">Err</span>(<span class="number">13</span>));\n<span class="kw">let </span>r = s.binary_search(<span class="kw-2">&amp;</span><span class="number">1</span>);\n<span class="macro">assert!</span>(<span class="kw">match </span>r { <span class="prelude-val">Ok</span>(<span class="number">1</span>..=<span class="number">4</span>) =&gt; <span class="bool-val">true</span>, <span class="kw">_ </span>=&gt; <span class="bool-val">false</span>, });</code></pre>'),
    ('binary_search_by', '<p>Binary searches this slice with a comparator function.</p>\n<p>The comparator function should return an order code that indicates\nwhether its argument is <code>Less</code>, <code>Equal</code> or <code>Greater</code> the desired\ntarget.\nIf the slice is not sorted or if the comparator function does not\nimplement an order consistent with the sort order of the underlying\nslice, the returned result is unspecified and meaningless.</p>\n<p>If the value is found then <a href="https://doc.rust-lang.org/1.95.0/core/result/enum.Result.html#variant.Ok" title="variant core::result::Result::Ok"><code>Result::Ok</code></a> is returned, containing the\nindex of the matching element. If there are multiple matches, then any\none of the matches could be returned. The index is chosen\ndeterministically, but is subject to change in future versions of Rust.\nIf the value is not found then <a href="https://doc.rust-lang.org/1.95.0/core/result/enum.Result.html#variant.Err" title="variant core::result::Result::Err"><code>Result::Err</code></a> is returned, containing\nthe index where a matching element could be inserted while maintaining\nsorted order.</p>\n<p>See also <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.binary_search" title="method slice::binary_search"><code>binary_search</code></a>, <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.binary_search_by_key" title="method slice::binary_search_by_key"><code>binary_search_by_key</code></a>, and <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.partition_point" title="method slice::partition_point"><code>partition_point</code></a>.</p>\n<h5 id="examples-78"><a class="doc-anchor" href="#examples-78">§</a>Examples</h5>\n<p>Looks up a series of four elements. The first is found, with a\nuniquely determined position; the second and third are not\nfound; the fourth could match any position in <code>[1, 4]</code>.</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>s = [<span class="number">0</span>, <span class="number">1</span>, <span class="number">1</span>, <span class="number">1</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">5</span>, <span class="number">8</span>, <span class="number">13</span>, <span class="number">21</span>, <span class="number">34</span>, <span class="number">55</span>];\n\n<span class="kw">let </span>seek = <span class="number">13</span>;\n<span class="macro">assert_eq!</span>(s.binary_search_by(|probe| probe.cmp(<span class="kw-2">&amp;</span>seek)), <span class="prelude-val">Ok</span>(<span class="number">9</span>));\n<span class="kw">let </span>seek = <span class="number">4</span>;\n<span class="macro">assert_eq!</span>(s.binary_search_by(|probe| probe.cmp(<span class="kw-2">&amp;</span>seek)), <span class="prelude-val">Err</span>(<span class="number">7</span>));\n<span class="kw">let </span>seek = <span class="number">100</span>;\n<span class="macro">assert_eq!</span>(s.binary_search_by(|probe| probe.cmp(<span class="kw-2">&amp;</span>seek)), <span class="prelude-val">Err</span>(<span class="number">13</span>));\n<span class="kw">let </span>seek = <span class="number">1</span>;\n<span class="kw">let </span>r = s.binary_search_by(|probe| probe.cmp(<span class="kw-2">&amp;</span>seek));\n<span class="macro">assert!</span>(<span class="kw">match </span>r { <span class="prelude-val">Ok</span>(<span class="number">1</span>..=<span class="number">4</span>) =&gt; <span class="bool-val">true</span>, <span class="kw">_ </span>=&gt; <span class="bool-val">false</span>, });</code></pre>'),
    ('binary_search_by_key', '<p>Binary searches this slice with a key extraction function.</p>\n<p>Assumes that the slice is sorted by the key, for instance with\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.sort_by_key" title="method slice::sort_by_key"><code>sort_by_key</code></a> using the same key extraction function.\nIf the slice is not sorted by the key, the returned result is\nunspecified and meaningless.</p>\n<p>If the value is found then <a href="https://doc.rust-lang.org/1.95.0/core/result/enum.Result.html#variant.Ok" title="variant core::result::Result::Ok"><code>Result::Ok</code></a> is returned, containing the\nindex of the matching element. If there are multiple matches, then any\none of the matches could be returned. The index is chosen\ndeterministically, but is subject to change in future versions of Rust.\nIf the value is not found then <a href="https://doc.rust-lang.org/1.95.0/core/result/enum.Result.html#variant.Err" title="variant core::result::Result::Err"><code>Result::Err</code></a> is returned, containing\nthe index where a matching element could be inserted while maintaining\nsorted order.</p>\n<p>See also <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.binary_search" title="method slice::binary_search"><code>binary_search</code></a>, <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.binary_search_by" title="method slice::binary_search_by"><code>binary_search_by</code></a>, and <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.partition_point" title="method slice::partition_point"><code>partition_point</code></a>.</p>\n<h5 id="examples-79"><a class="doc-anchor" href="#examples-79">§</a>Examples</h5>\n<p>Looks up a series of four elements in a slice of pairs sorted by\ntheir second elements. The first is found, with a uniquely\ndetermined position; the second and third are not found; the\nfourth could match any position in <code>[1, 4]</code>.</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>s = [(<span class="number">0</span>, <span class="number">0</span>), (<span class="number">2</span>, <span class="number">1</span>), (<span class="number">4</span>, <span class="number">1</span>), (<span class="number">5</span>, <span class="number">1</span>), (<span class="number">3</span>, <span class="number">1</span>),\n         (<span class="number">1</span>, <span class="number">2</span>), (<span class="number">2</span>, <span class="number">3</span>), (<span class="number">4</span>, <span class="number">5</span>), (<span class="number">5</span>, <span class="number">8</span>), (<span class="number">3</span>, <span class="number">13</span>),\n         (<span class="number">1</span>, <span class="number">21</span>), (<span class="number">2</span>, <span class="number">34</span>), (<span class="number">4</span>, <span class="number">55</span>)];\n\n<span class="macro">assert_eq!</span>(s.binary_search_by_key(<span class="kw-2">&amp;</span><span class="number">13</span>, |<span class="kw-2">&amp;</span>(a, b)| b),  <span class="prelude-val">Ok</span>(<span class="number">9</span>));\n<span class="macro">assert_eq!</span>(s.binary_search_by_key(<span class="kw-2">&amp;</span><span class="number">4</span>, |<span class="kw-2">&amp;</span>(a, b)| b),   <span class="prelude-val">Err</span>(<span class="number">7</span>));\n<span class="macro">assert_eq!</span>(s.binary_search_by_key(<span class="kw-2">&amp;</span><span class="number">100</span>, |<span class="kw-2">&amp;</span>(a, b)| b), <span class="prelude-val">Err</span>(<span class="number">13</span>));\n<span class="kw">let </span>r = s.binary_search_by_key(<span class="kw-2">&amp;</span><span class="number">1</span>, |<span class="kw-2">&amp;</span>(a, b)| b);\n<span class="macro">assert!</span>(<span class="kw">match </span>r { <span class="prelude-val">Ok</span>(<span class="number">1</span>..=<span class="number">4</span>) =&gt; <span class="bool-val">true</span>, <span class="kw">_ </span>=&gt; <span class="bool-val">false</span>, });</code></pre>'),
    ('sort_unstable', '<p>Sorts the slice in ascending order <strong>without</strong> preserving the initial order of equal elements.</p>\n<p>This sort is unstable (i.e., may reorder equal elements), in-place (i.e., does not\nallocate), and <em>O</em>(<em>n</em> * log(<em>n</em>)) worst-case.</p>\n<p>If the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>T</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, the function\nmay panic; even if the function exits normally, the resulting order of elements in the slice\nis unspecified. See also the note on panicking below.</p>\n<p>For example <code>|a, b| (a - b).cmp(a)</code> is a comparison function that is neither transitive nor\nreflexive nor total, <code>a &lt; b &lt; c &lt; a</code> with <code>a = 1, b = 2, c = 3</code>. For more information and\nexamples see the <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> documentation.</p>\n<p>All original elements will remain in the slice and any possible modifications via interior\nmutability are observed in the input. Same is true if the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>T</code> panics.</p>\n<p>Sorting types that only implement <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.PartialOrd.html" title="trait core::cmp::PartialOrd"><code>PartialOrd</code></a> such as <a href="https://doc.rust-lang.org/1.95.0/std/primitive.f32.html" title="primitive f32"><code>f32</code></a> and <a href="https://doc.rust-lang.org/1.95.0/std/primitive.f64.html" title="primitive f64"><code>f64</code></a> require\nadditional precautions. For example, <code>f32::NAN != f32::NAN</code>, which doesn’t fulfill the\nreflexivity requirement of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a>. By using an alternative comparison function with\n<code>slice::sort_unstable_by</code> such as <a href="https://doc.rust-lang.org/1.95.0/std/primitive.f32.html#method.total_cmp" title="method f32::total_cmp"><code>f32::total_cmp</code></a> or <a href="https://doc.rust-lang.org/1.95.0/std/primitive.f64.html#method.total_cmp" title="method f64::total_cmp"><code>f64::total_cmp</code></a> that defines a\n<a href="https://en.wikipedia.org/wiki/Total_order">total order</a> users can sort slices containing floating-point values. Alternatively, if all\nvalues in the slice are guaranteed to be in a subset for which <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.PartialOrd.html#tymethod.partial_cmp" title="method core::cmp::PartialOrd::partial_cmp"><code>PartialOrd::partial_cmp</code></a>\nforms a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, it’s possible to sort the slice with <code>sort_unstable_by(|a, b| a.partial_cmp(b).unwrap())</code>.</p>\n<h5 id="current-implementation"><a class="doc-anchor" href="#current-implementation">§</a>Current implementation</h5>\n<p>The current implementation is based on <a href="https://github.com/Voultapher/sort-research-rs/tree/main/ipnsort">ipnsort</a> by Lukas Bergdoll and Orson Peters, which\ncombines the fast average case of quicksort with the fast worst case of heapsort, achieving\nlinear time on fully sorted and reversed inputs. On inputs with k distinct elements, the\nexpected time to sort the data is <em>O</em>(<em>n</em> * log(<em>k</em>)).</p>\n<p>It is typically faster than stable sorting, except in a few special cases, e.g., when the\nslice is partially sorted.</p>\n<h5 id="panics-17"><a class="doc-anchor" href="#panics-17">§</a>Panics</h5>\n<p>May panic if the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>T</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, or if\nthe <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> implementation panics.</p>\n<h5 id="examples-80"><a class="doc-anchor" href="#examples-80">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">4</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>];\n\nv.sort_unstable();\n<span class="macro">assert_eq!</span>(v, [-<span class="number">5</span>, -<span class="number">3</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>]);</code></pre>'),
    ('sort_unstable_by', '<p>Sorts the slice in ascending order with a comparison function, <strong>without</strong> preserving the\ninitial order of equal elements.</p>\n<p>This sort is unstable (i.e., may reorder equal elements), in-place (i.e., does not\nallocate), and <em>O</em>(<em>n</em> * log(<em>n</em>)) worst-case.</p>\n<p>If the comparison function <code>compare</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, the function\nmay panic; even if the function exits normally, the resulting order of elements in the slice\nis unspecified. See also the note on panicking below.</p>\n<p>For example <code>|a, b| (a - b).cmp(a)</code> is a comparison function that is neither transitive nor\nreflexive nor total, <code>a &lt; b &lt; c &lt; a</code> with <code>a = 1, b = 2, c = 3</code>. For more information and\nexamples see the <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> documentation.</p>\n<p>All original elements will remain in the slice and any possible modifications via interior\nmutability are observed in the input. Same is true if <code>compare</code> panics.</p>\n<h5 id="current-implementation-1"><a class="doc-anchor" href="#current-implementation-1">§</a>Current implementation</h5>\n<p>The current implementation is based on <a href="https://github.com/Voultapher/sort-research-rs/tree/main/ipnsort">ipnsort</a> by Lukas Bergdoll and Orson Peters, which\ncombines the fast average case of quicksort with the fast worst case of heapsort, achieving\nlinear time on fully sorted and reversed inputs. On inputs with k distinct elements, the\nexpected time to sort the data is <em>O</em>(<em>n</em> * log(<em>k</em>)).</p>\n<p>It is typically faster than stable sorting, except in a few special cases, e.g., when the\nslice is partially sorted.</p>\n<h5 id="panics-18"><a class="doc-anchor" href="#panics-18">§</a>Panics</h5>\n<p>May panic if the <code>compare</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, or if\nthe <code>compare</code> itself panics.</p>\n<h5 id="examples-81"><a class="doc-anchor" href="#examples-81">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">4</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>];\nv.sort_unstable_by(|a, b| a.cmp(b));\n<span class="macro">assert_eq!</span>(v, [-<span class="number">5</span>, -<span class="number">3</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>]);\n\n<span class="comment">// reverse sorting\n</span>v.sort_unstable_by(|a, b| b.cmp(a));\n<span class="macro">assert_eq!</span>(v, [<span class="number">4</span>, <span class="number">2</span>, <span class="number">1</span>, -<span class="number">3</span>, -<span class="number">5</span>]);</code></pre>'),
    ('sort_unstable_by_key', '<p>Sorts the slice in ascending order with a key extraction function, <strong>without</strong> preserving\nthe initial order of equal elements.</p>\n<p>This sort is unstable (i.e., may reorder equal elements), in-place (i.e., does not\nallocate), and <em>O</em>(<em>n</em> * log(<em>n</em>)) worst-case.</p>\n<p>If the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>K</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, the function\nmay panic; even if the function exits normally, the resulting order of elements in the slice\nis unspecified. See also the note on panicking below.</p>\n<p>For example <code>|a, b| (a - b).cmp(a)</code> is a comparison function that is neither transitive nor\nreflexive nor total, <code>a &lt; b &lt; c &lt; a</code> with <code>a = 1, b = 2, c = 3</code>. For more information and\nexamples see the <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> documentation.</p>\n<p>All original elements will remain in the slice and any possible modifications via interior\nmutability are observed in the input. Same is true if the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>K</code> panics.</p>\n<h5 id="current-implementation-2"><a class="doc-anchor" href="#current-implementation-2">§</a>Current implementation</h5>\n<p>The current implementation is based on <a href="https://github.com/Voultapher/sort-research-rs/tree/main/ipnsort">ipnsort</a> by Lukas Bergdoll and Orson Peters, which\ncombines the fast average case of quicksort with the fast worst case of heapsort, achieving\nlinear time on fully sorted and reversed inputs. On inputs with k distinct elements, the\nexpected time to sort the data is <em>O</em>(<em>n</em> * log(<em>k</em>)).</p>\n<p>It is typically faster than stable sorting, except in a few special cases, e.g., when the\nslice is partially sorted.</p>\n<h5 id="panics-19"><a class="doc-anchor" href="#panics-19">§</a>Panics</h5>\n<p>May panic if the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>K</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, or if\nthe <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> implementation panics.</p>\n<h5 id="examples-82"><a class="doc-anchor" href="#examples-82">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">4i32</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>];\n\nv.sort_unstable_by_key(|k| k.abs());\n<span class="macro">assert_eq!</span>(v, [<span class="number">1</span>, <span class="number">2</span>, -<span class="number">3</span>, <span class="number">4</span>, -<span class="number">5</span>]);</code></pre>'),
    ('partial_sort_unstable', '<p>Partially sorts the slice in ascending order <strong>without</strong> preserving the initial order of equal elements.</p>\n<p>Upon completion, for the specified range <code>start..end</code>, it’s guaranteed that:</p>\n<ol>\n<li>Every element in <code>self[..start]</code> is smaller than or equal to</li>\n<li>Every element in <code>self[start..end]</code>, which is sorted, and smaller than or equal to</li>\n<li>Every element in <code>self[end..]</code>.</li>\n</ol>\n<p>This partial sort is unstable, meaning it may reorder equal elements in the specified range.\nIt may reorder elements outside the specified range as well, but the guarantees above still hold.</p>\n<p>This partial sort is in-place (i.e., does not allocate), and <em>O</em>(<em>n</em> + <em>k</em> * log(<em>k</em>)) worst-case,\nwhere <em>n</em> is the length of the slice and <em>k</em> is the length of the specified range.</p>\n<p>See the documentation of <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.sort_unstable" title="method slice::sort_unstable"><code>sort_unstable</code></a> for implementation notes.</p>\n<h5 id="panics-20"><a class="doc-anchor" href="#panics-20">§</a>Panics</h5>\n<p>May panic if the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>T</code> does not implement a total order, or if\nthe <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> implementation panics, or if the specified range is out of bounds.</p>\n<h5 id="examples-83"><a class="doc-anchor" href="#examples-83">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(slice_partial_sort_unstable)]\n\n</span><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">4</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>];\n\n<span class="comment">// empty range at the beginning, nothing changed\n</span>v.partial_sort_unstable(<span class="number">0</span>..<span class="number">0</span>);\n<span class="macro">assert_eq!</span>(v, [<span class="number">4</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>]);\n\n<span class="comment">// empty range in the middle, partitioning the slice\n</span>v.partial_sort_unstable(<span class="number">2</span>..<span class="number">2</span>);\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">0</span>..<span class="number">2 </span>{\n   <span class="macro">assert!</span>(v[i] &lt;= v[<span class="number">2</span>]);\n}\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">3</span>..v.len() {\n  <span class="macro">assert!</span>(v[<span class="number">2</span>] &lt;= v[i]);\n}\n\n<span class="comment">// single element range, same as select_nth_unstable\n</span>v.partial_sort_unstable(<span class="number">2</span>..<span class="number">3</span>);\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">0</span>..<span class="number">2 </span>{\n   <span class="macro">assert!</span>(v[i] &lt;= v[<span class="number">2</span>]);\n}\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">3</span>..v.len() {\n  <span class="macro">assert!</span>(v[<span class="number">2</span>] &lt;= v[i]);\n}\n\n<span class="comment">// partial sort a subrange\n</span>v.partial_sort_unstable(<span class="number">1</span>..<span class="number">4</span>);\n<span class="macro">assert_eq!</span>(<span class="kw-2">&amp;</span>v[<span class="number">1</span>..<span class="number">4</span>], [-<span class="number">3</span>, <span class="number">1</span>, <span class="number">2</span>]);\n\n<span class="comment">// partial sort the whole range, same as sort_unstable\n</span>v.partial_sort_unstable(..);\n<span class="macro">assert_eq!</span>(v, [-<span class="number">5</span>, -<span class="number">3</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>]);</code></pre>'),
    ('partial_sort_unstable_by', '<p>Partially sorts the slice in ascending order with a comparison function, <strong>without</strong>\npreserving the initial order of equal elements.</p>\n<p>Upon completion, for the specified range <code>start..end</code>, it’s guaranteed that:</p>\n<ol>\n<li>Every element in <code>self[..start]</code> is smaller than or equal to</li>\n<li>Every element in <code>self[start..end]</code>, which is sorted, and smaller than or equal to</li>\n<li>Every element in <code>self[end..]</code>.</li>\n</ol>\n<p>This partial sort is unstable, meaning it may reorder equal elements in the specified range.\nIt may reorder elements outside the specified range as well, but the guarantees above still hold.</p>\n<p>This partial sort is in-place (i.e., does not allocate), and <em>O</em>(<em>n</em> + <em>k</em> * log(<em>k</em>)) worst-case,\nwhere <em>n</em> is the length of the slice and <em>k</em> is the length of the specified range.</p>\n<p>See the documentation of <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.sort_unstable_by" title="method slice::sort_unstable_by"><code>sort_unstable_by</code></a> for implementation notes.</p>\n<h5 id="panics-21"><a class="doc-anchor" href="#panics-21">§</a>Panics</h5>\n<p>May panic if the <code>compare</code> does not implement a total order, or if\nthe <code>compare</code> itself panics, or if the specified range is out of bounds.</p>\n<h5 id="examples-84"><a class="doc-anchor" href="#examples-84">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(slice_partial_sort_unstable)]\n\n</span><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">4</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>];\n\n<span class="comment">// empty range at the beginning, nothing changed\n</span>v.partial_sort_unstable_by(<span class="number">0</span>..<span class="number">0</span>, |a, b| b.cmp(a));\n<span class="macro">assert_eq!</span>(v, [<span class="number">4</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>]);\n\n<span class="comment">// empty range in the middle, partitioning the slice\n</span>v.partial_sort_unstable_by(<span class="number">2</span>..<span class="number">2</span>, |a, b| b.cmp(a));\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">0</span>..<span class="number">2 </span>{\n   <span class="macro">assert!</span>(v[i] &gt;= v[<span class="number">2</span>]);\n}\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">3</span>..v.len() {\n  <span class="macro">assert!</span>(v[<span class="number">2</span>] &gt;= v[i]);\n}\n\n<span class="comment">// single element range, same as select_nth_unstable\n</span>v.partial_sort_unstable_by(<span class="number">2</span>..<span class="number">3</span>, |a, b| b.cmp(a));\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">0</span>..<span class="number">2 </span>{\n   <span class="macro">assert!</span>(v[i] &gt;= v[<span class="number">2</span>]);\n}\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">3</span>..v.len() {\n  <span class="macro">assert!</span>(v[<span class="number">2</span>] &gt;= v[i]);\n}\n\n<span class="comment">// partial sort a subrange\n</span>v.partial_sort_unstable_by(<span class="number">1</span>..<span class="number">4</span>, |a, b| b.cmp(a));\n<span class="macro">assert_eq!</span>(<span class="kw-2">&amp;</span>v[<span class="number">1</span>..<span class="number">4</span>], [<span class="number">2</span>, <span class="number">1</span>, -<span class="number">3</span>]);\n\n<span class="comment">// partial sort the whole range, same as sort_unstable\n</span>v.partial_sort_unstable_by(.., |a, b| b.cmp(a));\n<span class="macro">assert_eq!</span>(v, [<span class="number">4</span>, <span class="number">2</span>, <span class="number">1</span>, -<span class="number">3</span>, -<span class="number">5</span>]);</code></pre>'),
    ('partial_sort_unstable_by_key', '<p>Partially sorts the slice in ascending order with a key extraction function, <strong>without</strong>\npreserving the initial order of equal elements.</p>\n<p>Upon completion, for the specified range <code>start..end</code>, it’s guaranteed that:</p>\n<ol>\n<li>Every element in <code>self[..start]</code> is smaller than or equal to</li>\n<li>Every element in <code>self[start..end]</code>, which is sorted, and smaller than or equal to</li>\n<li>Every element in <code>self[end..]</code>.</li>\n</ol>\n<p>This partial sort is unstable, meaning it may reorder equal elements in the specified range.\nIt may reorder elements outside the specified range as well, but the guarantees above still hold.</p>\n<p>This partial sort is in-place (i.e., does not allocate), and <em>O</em>(<em>n</em> + <em>k</em> * log(<em>k</em>)) worst-case,\nwhere <em>n</em> is the length of the slice and <em>k</em> is the length of the specified range.</p>\n<p>See the documentation of <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.sort_unstable_by_key" title="method slice::sort_unstable_by_key"><code>sort_unstable_by_key</code></a> for implementation notes.</p>\n<h5 id="panics-22"><a class="doc-anchor" href="#panics-22">§</a>Panics</h5>\n<p>May panic if the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>K</code> does not implement a total order, or if\nthe <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> implementation panics, or if the specified range is out of bounds.</p>\n<h5 id="examples-85"><a class="doc-anchor" href="#examples-85">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(slice_partial_sort_unstable)]\n\n</span><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">4i32</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>];\n\n<span class="comment">// empty range at the beginning, nothing changed\n</span>v.partial_sort_unstable_by_key(<span class="number">0</span>..<span class="number">0</span>, |k| k.abs());\n<span class="macro">assert_eq!</span>(v, [<span class="number">4</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>]);\n\n<span class="comment">// empty range in the middle, partitioning the slice\n</span>v.partial_sort_unstable_by_key(<span class="number">2</span>..<span class="number">2</span>, |k| k.abs());\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">0</span>..<span class="number">2 </span>{\n   <span class="macro">assert!</span>(v[i].abs() &lt;= v[<span class="number">2</span>].abs());\n}\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">3</span>..v.len() {\n  <span class="macro">assert!</span>(v[<span class="number">2</span>].abs() &lt;= v[i].abs());\n}\n\n<span class="comment">// single element range, same as select_nth_unstable\n</span>v.partial_sort_unstable_by_key(<span class="number">2</span>..<span class="number">3</span>, |k| k.abs());\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">0</span>..<span class="number">2 </span>{\n   <span class="macro">assert!</span>(v[i].abs() &lt;= v[<span class="number">2</span>].abs());\n}\n<span class="kw">for </span>i <span class="kw">in </span><span class="number">3</span>..v.len() {\n  <span class="macro">assert!</span>(v[<span class="number">2</span>].abs() &lt;= v[i].abs());\n}\n\n<span class="comment">// partial sort a subrange\n</span>v.partial_sort_unstable_by_key(<span class="number">1</span>..<span class="number">4</span>, |k| k.abs());\n<span class="macro">assert_eq!</span>(<span class="kw-2">&amp;</span>v[<span class="number">1</span>..<span class="number">4</span>], [<span class="number">2</span>, -<span class="number">3</span>, <span class="number">4</span>]);\n\n<span class="comment">// partial sort the whole range, same as sort_unstable\n</span>v.partial_sort_unstable_by_key(.., |k| k.abs());\n<span class="macro">assert_eq!</span>(v, [<span class="number">1</span>, <span class="number">2</span>, -<span class="number">3</span>, <span class="number">4</span>, -<span class="number">5</span>]);</code></pre>'),
    ('select_nth_unstable', '<p>Reorders the slice such that the element at <code>index</code> is at a sort-order position. All\nelements before <code>index</code> will be <code>&lt;=</code> to this value, and all elements after will be <code>&gt;=</code> to\nit.</p>\n<p>This reordering is unstable (i.e. any element that compares equal to the nth element may end\nup at that position), in-place (i.e.  does not allocate), and runs in <em>O</em>(<em>n</em>) time. This\nfunction is also known as “kth element” in other libraries.</p>\n<p>Returns a triple that partitions the reordered slice:</p>\n<ul>\n<li>\n<p>The unsorted subslice before <code>index</code>, whose elements all satisfy <code>x &lt;= self[index]</code>.</p>\n</li>\n<li>\n<p>The element at <code>index</code>.</p>\n</li>\n<li>\n<p>The unsorted subslice after <code>index</code>, whose elements all satisfy <code>x &gt;= self[index]</code>.</p>\n</li>\n</ul>\n<h5 id="current-implementation-3"><a class="doc-anchor" href="#current-implementation-3">§</a>Current implementation</h5>\n<p>The current algorithm is an introselect implementation based on <a href="https://github.com/Voultapher/sort-research-rs/tree/main/ipnsort">ipnsort</a> by Lukas Bergdoll\nand Orson Peters, which is also the basis for <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.sort_unstable" title="method slice::sort_unstable"><code>sort_unstable</code></a>. The fallback algorithm is\nMedian of Medians using Tukey’s Ninther for pivot selection, which guarantees linear runtime\nfor all inputs.</p>\n<h5 id="panics-23"><a class="doc-anchor" href="#panics-23">§</a>Panics</h5>\n<p>Panics when <code>index &gt;= len()</code>, and so always panics on empty slices.</p>\n<p>May panic if the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>T</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>.</p>\n<h5 id="examples-86"><a class="doc-anchor" href="#examples-86">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [-<span class="number">5i32</span>, <span class="number">4</span>, <span class="number">2</span>, -<span class="number">3</span>, <span class="number">1</span>];\n\n<span class="comment">// Find the items `&lt;=` to the median, the median itself, and the items `&gt;=` to it.\n</span><span class="kw">let </span>(lesser, median, greater) = v.select_nth_unstable(<span class="number">2</span>);\n\n<span class="macro">assert!</span>(lesser == [-<span class="number">3</span>, -<span class="number">5</span>] || lesser == [-<span class="number">5</span>, -<span class="number">3</span>]);\n<span class="macro">assert_eq!</span>(median, <span class="kw-2">&amp;mut </span><span class="number">1</span>);\n<span class="macro">assert!</span>(greater == [<span class="number">4</span>, <span class="number">2</span>] || greater == [<span class="number">2</span>, <span class="number">4</span>]);\n\n<span class="comment">// We are only guaranteed the slice will be one of the following, based on the way we sort\n// about the specified index.\n</span><span class="macro">assert!</span>(v == [-<span class="number">3</span>, -<span class="number">5</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>] ||\n        v == [-<span class="number">5</span>, -<span class="number">3</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>] ||\n        v == [-<span class="number">3</span>, -<span class="number">5</span>, <span class="number">1</span>, <span class="number">4</span>, <span class="number">2</span>] ||\n        v == [-<span class="number">5</span>, -<span class="number">3</span>, <span class="number">1</span>, <span class="number">4</span>, <span class="number">2</span>]);</code></pre>'),
    ('select_nth_unstable_by', '<p>Reorders the slice with a comparator function such that the element at <code>index</code> is at a\nsort-order position. All elements before <code>index</code> will be <code>&lt;=</code> to this value, and all\nelements after will be <code>&gt;=</code> to it, according to the comparator function.</p>\n<p>This reordering is unstable (i.e. any element that compares equal to the nth element may end\nup at that position), in-place (i.e.  does not allocate), and runs in <em>O</em>(<em>n</em>) time. This\nfunction is also known as “kth element” in other libraries.</p>\n<p>Returns a triple partitioning the reordered slice:</p>\n<ul>\n<li>\n<p>The unsorted subslice before <code>index</code>, whose elements all satisfy\n<code>compare(x, self[index]).is_le()</code>.</p>\n</li>\n<li>\n<p>The element at <code>index</code>.</p>\n</li>\n<li>\n<p>The unsorted subslice after <code>index</code>, whose elements all satisfy\n<code>compare(x, self[index]).is_ge()</code>.</p>\n</li>\n</ul>\n<h5 id="current-implementation-4"><a class="doc-anchor" href="#current-implementation-4">§</a>Current implementation</h5>\n<p>The current algorithm is an introselect implementation based on <a href="https://github.com/Voultapher/sort-research-rs/tree/main/ipnsort">ipnsort</a> by Lukas Bergdoll\nand Orson Peters, which is also the basis for <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.sort_unstable" title="method slice::sort_unstable"><code>sort_unstable</code></a>. The fallback algorithm is\nMedian of Medians using Tukey’s Ninther for pivot selection, which guarantees linear runtime\nfor all inputs.</p>\n<h5 id="panics-24"><a class="doc-anchor" href="#panics-24">§</a>Panics</h5>\n<p>Panics when <code>index &gt;= len()</code>, and so always panics on empty slices.</p>\n<p>May panic if <code>compare</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>.</p>\n<h5 id="examples-87"><a class="doc-anchor" href="#examples-87">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [-<span class="number">5i32</span>, <span class="number">4</span>, <span class="number">2</span>, -<span class="number">3</span>, <span class="number">1</span>];\n\n<span class="comment">// Find the items `&gt;=` to the median, the median itself, and the items `&lt;=` to it, by using\n// a reversed comparator.\n</span><span class="kw">let </span>(before, median, after) = v.select_nth_unstable_by(<span class="number">2</span>, |a, b| b.cmp(a));\n\n<span class="macro">assert!</span>(before == [<span class="number">4</span>, <span class="number">2</span>] || before == [<span class="number">2</span>, <span class="number">4</span>]);\n<span class="macro">assert_eq!</span>(median, <span class="kw-2">&amp;mut </span><span class="number">1</span>);\n<span class="macro">assert!</span>(after == [-<span class="number">3</span>, -<span class="number">5</span>] || after == [-<span class="number">5</span>, -<span class="number">3</span>]);\n\n<span class="comment">// We are only guaranteed the slice will be one of the following, based on the way we sort\n// about the specified index.\n</span><span class="macro">assert!</span>(v == [<span class="number">2</span>, <span class="number">4</span>, <span class="number">1</span>, -<span class="number">5</span>, -<span class="number">3</span>] ||\n        v == [<span class="number">2</span>, <span class="number">4</span>, <span class="number">1</span>, -<span class="number">3</span>, -<span class="number">5</span>] ||\n        v == [<span class="number">4</span>, <span class="number">2</span>, <span class="number">1</span>, -<span class="number">5</span>, -<span class="number">3</span>] ||\n        v == [<span class="number">4</span>, <span class="number">2</span>, <span class="number">1</span>, -<span class="number">3</span>, -<span class="number">5</span>]);</code></pre>'),
    ('select_nth_unstable_by_key', '<p>Reorders the slice with a key extraction function such that the element at <code>index</code> is at a\nsort-order position. All elements before <code>index</code> will have keys <code>&lt;=</code> to the key at <code>index</code>,\nand all elements after will have keys <code>&gt;=</code> to it.</p>\n<p>This reordering is unstable (i.e. any element that compares equal to the nth element may end\nup at that position), in-place (i.e.  does not allocate), and runs in <em>O</em>(<em>n</em>) time. This\nfunction is also known as “kth element” in other libraries.</p>\n<p>Returns a triple partitioning the reordered slice:</p>\n<ul>\n<li>\n<p>The unsorted subslice before <code>index</code>, whose elements all satisfy <code>f(x) &lt;= f(self[index])</code>.</p>\n</li>\n<li>\n<p>The element at <code>index</code>.</p>\n</li>\n<li>\n<p>The unsorted subslice after <code>index</code>, whose elements all satisfy <code>f(x) &gt;= f(self[index])</code>.</p>\n</li>\n</ul>\n<h5 id="current-implementation-5"><a class="doc-anchor" href="#current-implementation-5">§</a>Current implementation</h5>\n<p>The current algorithm is an introselect implementation based on <a href="https://github.com/Voultapher/sort-research-rs/tree/main/ipnsort">ipnsort</a> by Lukas Bergdoll\nand Orson Peters, which is also the basis for <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.sort_unstable" title="method slice::sort_unstable"><code>sort_unstable</code></a>. The fallback algorithm is\nMedian of Medians using Tukey’s Ninther for pivot selection, which guarantees linear runtime\nfor all inputs.</p>\n<h5 id="panics-25"><a class="doc-anchor" href="#panics-25">§</a>Panics</h5>\n<p>Panics when <code>index &gt;= len()</code>, meaning it always panics on empty slices.</p>\n<p>May panic if <code>K: Ord</code> does not implement a total order.</p>\n<h5 id="examples-88"><a class="doc-anchor" href="#examples-88">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [-<span class="number">5i32</span>, <span class="number">4</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>];\n\n<span class="comment">// Find the items `&lt;=` to the absolute median, the absolute median itself, and the items\n// `&gt;=` to it.\n</span><span class="kw">let </span>(lesser, median, greater) = v.select_nth_unstable_by_key(<span class="number">2</span>, |a| a.abs());\n\n<span class="macro">assert!</span>(lesser == [<span class="number">1</span>, <span class="number">2</span>] || lesser == [<span class="number">2</span>, <span class="number">1</span>]);\n<span class="macro">assert_eq!</span>(median, <span class="kw-2">&amp;mut </span>-<span class="number">3</span>);\n<span class="macro">assert!</span>(greater == [<span class="number">4</span>, -<span class="number">5</span>] || greater == [-<span class="number">5</span>, <span class="number">4</span>]);\n\n<span class="comment">// We are only guaranteed the slice will be one of the following, based on the way we sort\n// about the specified index.\n</span><span class="macro">assert!</span>(v == [<span class="number">1</span>, <span class="number">2</span>, -<span class="number">3</span>, <span class="number">4</span>, -<span class="number">5</span>] ||\n        v == [<span class="number">1</span>, <span class="number">2</span>, -<span class="number">3</span>, -<span class="number">5</span>, <span class="number">4</span>] ||\n        v == [<span class="number">2</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">4</span>, -<span class="number">5</span>] ||\n        v == [<span class="number">2</span>, <span class="number">1</span>, -<span class="number">3</span>, -<span class="number">5</span>, <span class="number">4</span>]);</code></pre>'),
    ('partition_dedup', '<p>Moves all consecutive repeated elements to the end of the slice according to the\n<a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.PartialEq.html" title="trait core::cmp::PartialEq"><code>PartialEq</code></a> trait implementation.</p>\n<p>Returns two slices. The first contains no consecutive repeated elements.\nThe second contains all the duplicates in no specified order.</p>\n<p>If the slice is sorted, the first returned slice contains no duplicates.</p>\n<h5 id="examples-89"><a class="doc-anchor" href="#examples-89">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(slice_partition_dedup)]\n\n</span><span class="kw">let </span><span class="kw-2">mut </span>slice = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">3</span>, <span class="number">2</span>, <span class="number">1</span>, <span class="number">1</span>];\n\n<span class="kw">let </span>(dedup, duplicates) = slice.partition_dedup();\n\n<span class="macro">assert_eq!</span>(dedup, [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">2</span>, <span class="number">1</span>]);\n<span class="macro">assert_eq!</span>(duplicates, [<span class="number">2</span>, <span class="number">3</span>, <span class="number">1</span>]);</code></pre>'),
    ('partition_dedup_by', '<p>Moves all but the first of consecutive elements to the end of the slice satisfying\na given equality relation.</p>\n<p>Returns two slices. The first contains no consecutive repeated elements.\nThe second contains all the duplicates in no specified order.</p>\n<p>The <code>same_bucket</code> function is passed references to two elements from the slice and\nmust determine if the elements compare equal. The elements are passed in opposite order\nfrom their order in the slice, so if <code>same_bucket(a, b)</code> returns <code>true</code>, <code>a</code> is moved\nat the end of the slice.</p>\n<p>If the slice is sorted, the first returned slice contains no duplicates.</p>\n<h5 id="examples-90"><a class="doc-anchor" href="#examples-90">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(slice_partition_dedup)]\n\n</span><span class="kw">let </span><span class="kw-2">mut </span>slice = [<span class="string">"foo"</span>, <span class="string">"Foo"</span>, <span class="string">"BAZ"</span>, <span class="string">"Bar"</span>, <span class="string">"bar"</span>, <span class="string">"baz"</span>, <span class="string">"BAZ"</span>];\n\n<span class="kw">let </span>(dedup, duplicates) = slice.partition_dedup_by(|a, b| a.eq_ignore_ascii_case(b));\n\n<span class="macro">assert_eq!</span>(dedup, [<span class="string">"foo"</span>, <span class="string">"BAZ"</span>, <span class="string">"Bar"</span>, <span class="string">"baz"</span>]);\n<span class="macro">assert_eq!</span>(duplicates, [<span class="string">"bar"</span>, <span class="string">"Foo"</span>, <span class="string">"BAZ"</span>]);</code></pre>'),
    ('partition_dedup_by_key', '<p>Moves all but the first of consecutive elements to the end of the slice that resolve\nto the same key.</p>\n<p>Returns two slices. The first contains no consecutive repeated elements.\nThe second contains all the duplicates in no specified order.</p>\n<p>If the slice is sorted, the first returned slice contains no duplicates.</p>\n<h5 id="examples-91"><a class="doc-anchor" href="#examples-91">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(slice_partition_dedup)]\n\n</span><span class="kw">let </span><span class="kw-2">mut </span>slice = [<span class="number">10</span>, <span class="number">20</span>, <span class="number">21</span>, <span class="number">30</span>, <span class="number">30</span>, <span class="number">20</span>, <span class="number">11</span>, <span class="number">13</span>];\n\n<span class="kw">let </span>(dedup, duplicates) = slice.partition_dedup_by_key(|i| <span class="kw-2">*</span>i / <span class="number">10</span>);\n\n<span class="macro">assert_eq!</span>(dedup, [<span class="number">10</span>, <span class="number">20</span>, <span class="number">30</span>, <span class="number">20</span>, <span class="number">11</span>]);\n<span class="macro">assert_eq!</span>(duplicates, [<span class="number">21</span>, <span class="number">30</span>, <span class="number">13</span>]);</code></pre>'),
    ('clone_from_slice', '<p>Copies the elements from <code>src</code> into <code>self</code>.</p>\n<p>The length of <code>src</code> must be the same as <code>self</code>.</p>\n<h5 id="panics-28"><a class="doc-anchor" href="#panics-28">§</a>Panics</h5>\n<p>This function will panic if the two slices have different lengths.</p>\n<h5 id="examples-98"><a class="doc-anchor" href="#examples-98">§</a>Examples</h5>\n<p>Cloning two elements from a slice into another:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>src = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">4</span>];\n<span class="kw">let </span><span class="kw-2">mut </span>dst = [<span class="number">0</span>, <span class="number">0</span>];\n\n<span class="comment">// Because the slices have to be the same length,\n// we slice the source slice from four elements\n// to two. It will panic if we don\'t do this.\n</span>dst.clone_from_slice(<span class="kw-2">&amp;</span>src[<span class="number">2</span>..]);\n\n<span class="macro">assert_eq!</span>(src, [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">4</span>]);\n<span class="macro">assert_eq!</span>(dst, [<span class="number">3</span>, <span class="number">4</span>]);</code></pre>'),
    ('copy_from_slice', '<p>Copies all elements from <code>src</code> into <code>self</code>, using a memcpy.</p>\n<p>The length of <code>src</code> must be the same as <code>self</code>.</p>\n<p>If <code>T</code> does not implement <code>Copy</code>, use <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.clone_from_slice" title="method slice::clone_from_slice"><code>clone_from_slice</code></a>.</p>\n<h5 id="panics-29"><a class="doc-anchor" href="#panics-29">§</a>Panics</h5>\n<p>This function will panic if the two slices have different lengths.</p>\n<h5 id="examples-99"><a class="doc-anchor" href="#examples-99">§</a>Examples</h5>\n<p>Copying two elements from a slice into another:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>src = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">4</span>];\n<span class="kw">let </span><span class="kw-2">mut </span>dst = [<span class="number">0</span>, <span class="number">0</span>];\n\n<span class="comment">// Because the slices have to be the same length,\n// we slice the source slice from four elements\n// to two. It will panic if we don\'t do this.\n</span>dst.copy_from_slice(<span class="kw-2">&amp;</span>src[<span class="number">2</span>..]);\n\n<span class="macro">assert_eq!</span>(src, [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">4</span>]);\n<span class="macro">assert_eq!</span>(dst, [<span class="number">3</span>, <span class="number">4</span>]);</code></pre>'),
    ('copy_within', '<p>Copies elements from one part of the slice to another part of itself,\nusing a memmove.</p>\n<p><code>src</code> is the range within <code>self</code> to copy from. <code>dest</code> is the starting\nindex of the range within <code>self</code> to copy to, which will have the same\nlength as <code>src</code>. The two ranges may overlap. The ends of the two ranges\nmust be less than or equal to <code>self.len()</code>.</p>\n<h5 id="panics-30"><a class="doc-anchor" href="#panics-30">§</a>Panics</h5>\n<p>This function will panic if either range exceeds the end of the slice,\nor if the end of <code>src</code> is before the start.</p>\n<h5 id="examples-100"><a class="doc-anchor" href="#examples-100">§</a>Examples</h5>\n<p>Copying four bytes within a slice:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>bytes = <span class="kw-2">*</span><span class="string">b"Hello, World!"</span>;\n\nbytes.copy_within(<span class="number">1</span>..<span class="number">5</span>, <span class="number">8</span>);\n\n<span class="macro">assert_eq!</span>(<span class="kw-2">&amp;</span>bytes, <span class="string">b"Hello, Wello!"</span>);</code></pre>'),
    ('swap_with_slice', '<p>Swaps all elements in <code>self</code> with those in <code>other</code>.</p>\n<p>The length of <code>other</code> must be the same as <code>self</code>.</p>\n<h5 id="panics-31"><a class="doc-anchor" href="#panics-31">§</a>Panics</h5>\n<p>This function will panic if the two slices have different lengths.</p>\n<h5 id="example"><a class="doc-anchor" href="#example">§</a>Example</h5>\n<p>Swapping two elements across slices:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>slice1 = [<span class="number">0</span>, <span class="number">0</span>];\n<span class="kw">let </span><span class="kw-2">mut </span>slice2 = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">4</span>];\n\nslice1.swap_with_slice(<span class="kw-2">&amp;mut </span>slice2[<span class="number">2</span>..]);\n\n<span class="macro">assert_eq!</span>(slice1, [<span class="number">3</span>, <span class="number">4</span>]);\n<span class="macro">assert_eq!</span>(slice2, [<span class="number">1</span>, <span class="number">2</span>, <span class="number">0</span>, <span class="number">0</span>]);</code></pre>'),
    ('align_to', '<p>Transmutes the slice to a slice of another type, ensuring alignment of the types is\nmaintained.</p>\n<p>This method splits the slice into three distinct slices: prefix, correctly aligned middle\nslice of a new type, and the suffix slice. The middle part will be as big as possible under\nthe given alignment constraint and element size.</p>\n<p>This method has no purpose when either input element <code>T</code> or output element <code>U</code> are\nzero-sized and will return the original slice without splitting anything.</p>\n<h5 id="safety-8"><a class="doc-anchor" href="#safety-8">§</a>Safety</h5>\n<p>This method is essentially a <code>transmute</code> with respect to the elements in the returned\nmiddle slice, so all the usual caveats pertaining to <code>transmute::&lt;T, U&gt;</code> also apply here.</p>\n<h5 id="examples-101"><a class="doc-anchor" href="#examples-101">§</a>Examples</h5>\n<p>Basic usage:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">unsafe </span>{\n    <span class="kw">let </span>bytes: [u8; <span class="number">7</span>] = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">4</span>, <span class="number">5</span>, <span class="number">6</span>, <span class="number">7</span>];\n    <span class="kw">let </span>(prefix, shorts, suffix) = bytes.align_to::&lt;u16&gt;();\n    <span class="comment">// less_efficient_algorithm_for_bytes(prefix);\n    // more_efficient_algorithm_for_aligned_shorts(shorts);\n    // less_efficient_algorithm_for_bytes(suffix);\n</span>}</code></pre>'),
    ('align_to_mut', '<p>Transmutes the mutable slice to a mutable slice of another type, ensuring alignment of the\ntypes is maintained.</p>\n<p>This method splits the slice into three distinct slices: prefix, correctly aligned middle\nslice of a new type, and the suffix slice. The middle part will be as big as possible under\nthe given alignment constraint and element size.</p>\n<p>This method has no purpose when either input element <code>T</code> or output element <code>U</code> are\nzero-sized and will return the original slice without splitting anything.</p>\n<h5 id="safety-9"><a class="doc-anchor" href="#safety-9">§</a>Safety</h5>\n<p>This method is essentially a <code>transmute</code> with respect to the elements in the returned\nmiddle slice, so all the usual caveats pertaining to <code>transmute::&lt;T, U&gt;</code> also apply here.</p>\n<h5 id="examples-102"><a class="doc-anchor" href="#examples-102">§</a>Examples</h5>\n<p>Basic usage:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">unsafe </span>{\n    <span class="kw">let </span><span class="kw-2">mut </span>bytes: [u8; <span class="number">7</span>] = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">4</span>, <span class="number">5</span>, <span class="number">6</span>, <span class="number">7</span>];\n    <span class="kw">let </span>(prefix, shorts, suffix) = bytes.align_to_mut::&lt;u16&gt;();\n    <span class="comment">// less_efficient_algorithm_for_bytes(prefix);\n    // more_efficient_algorithm_for_aligned_shorts(shorts);\n    // less_efficient_algorithm_for_bytes(suffix);\n</span>}</code></pre>'),
    ('as_simd', '<p>Splits a slice into a prefix, a middle of aligned SIMD types, and a suffix.</p>\n<p>This is a safe wrapper around <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.align_to" title="method slice::align_to"><code>slice::align_to</code></a>, so inherits the same\nguarantees as that method.</p>\n<h5 id="panics-32"><a class="doc-anchor" href="#panics-32">§</a>Panics</h5>\n<p>This will panic if the size of the SIMD type is different from\n<code>LANES</code> times that of the scalar.</p>\n<p>At the time of writing, the trait restrictions on <code>Simd&lt;T, LANES&gt;</code> keeps\nthat from ever happening, as only power-of-two numbers of lanes are\nsupported.  It’s possible that, in the future, those restrictions might\nbe lifted in a way that would make it possible to see panics from this\nmethod for something like <code>LANES == 3</code>.</p>\n<h5 id="examples-103"><a class="doc-anchor" href="#examples-103">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(portable_simd)]\n</span><span class="kw">use </span>core::simd::prelude::<span class="kw-2">*</span>;\n\n<span class="kw">let </span>short = <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>];\n<span class="kw">let </span>(prefix, middle, suffix) = short.as_simd::&lt;<span class="number">4</span>&gt;();\n<span class="macro">assert_eq!</span>(middle, []); <span class="comment">// Not enough elements for anything in the middle\n\n// They might be split in any possible way between prefix and suffix\n</span><span class="kw">let </span>it = prefix.iter().chain(suffix).copied();\n<span class="macro">assert_eq!</span>(it.collect::&lt;Vec&lt;<span class="kw">_</span>&gt;&gt;(), <span class="macro">vec!</span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>]);\n\n<span class="kw">fn </span>basic_simd_sum(x: <span class="kw-2">&amp;</span>[f32]) -&gt; f32 {\n    <span class="kw">use </span>std::ops::Add;\n    <span class="kw">let </span>(prefix, middle, suffix) = x.as_simd();\n    <span class="kw">let </span>sums = f32x4::from_array([\n        prefix.iter().copied().sum(),\n        <span class="number">0.0</span>,\n        <span class="number">0.0</span>,\n        suffix.iter().copied().sum(),\n    ]);\n    <span class="kw">let </span>sums = middle.iter().copied().fold(sums, f32x4::add);\n    sums.reduce_sum()\n}\n\n<span class="kw">let </span>numbers: Vec&lt;f32&gt; = (<span class="number">1</span>..<span class="number">101</span>).map(|x| x <span class="kw">as _</span>).collect();\n<span class="macro">assert_eq!</span>(basic_simd_sum(<span class="kw-2">&amp;</span>numbers[<span class="number">1</span>..<span class="number">99</span>]), <span class="number">4949.0</span>);</code></pre>'),
    ('as_simd_mut', '<p>Splits a mutable slice into a mutable prefix, a middle of aligned SIMD types,\nand a mutable suffix.</p>\n<p>This is a safe wrapper around <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.align_to_mut" title="method slice::align_to_mut"><code>slice::align_to_mut</code></a>, so inherits the same\nguarantees as that method.</p>\n<p>This is the mutable version of <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.as_simd" title="method slice::as_simd"><code>slice::as_simd</code></a>; see that for examples.</p>\n<h5 id="panics-33"><a class="doc-anchor" href="#panics-33">§</a>Panics</h5>\n<p>This will panic if the size of the SIMD type is different from\n<code>LANES</code> times that of the scalar.</p>\n<p>At the time of writing, the trait restrictions on <code>Simd&lt;T, LANES&gt;</code> keeps\nthat from ever happening, as only power-of-two numbers of lanes are\nsupported.  It’s possible that, in the future, those restrictions might\nbe lifted in a way that would make it possible to see panics from this\nmethod for something like <code>LANES == 3</code>.</p>\n'),
    ('is_sorted', '<p>Checks if the elements of this slice are sorted.</p>\n<p>That is, for each element <code>a</code> and its following element <code>b</code>, <code>a &lt;= b</code> must hold. If the\nslice yields exactly zero or one element, <code>true</code> is returned.</p>\n<p>Note that if <code>Self::Item</code> is only <code>PartialOrd</code>, but not <code>Ord</code>, the above definition\nimplies that this function returns <code>false</code> if any two consecutive items are not\ncomparable.</p>\n<h5 id="examples-104"><a class="doc-anchor" href="#examples-104">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>empty: [i32; <span class="number">0</span>] = [];\n\n<span class="macro">assert!</span>([<span class="number">1</span>, <span class="number">2</span>, <span class="number">2</span>, <span class="number">9</span>].is_sorted());\n<span class="macro">assert!</span>(![<span class="number">1</span>, <span class="number">3</span>, <span class="number">2</span>, <span class="number">4</span>].is_sorted());\n<span class="macro">assert!</span>([<span class="number">0</span>].is_sorted());\n<span class="macro">assert!</span>(empty.is_sorted());\n<span class="macro">assert!</span>(![<span class="number">0.0</span>, <span class="number">1.0</span>, f32::NAN].is_sorted());</code></pre>'),
    ('is_sorted_by', '<p>Checks if the elements of this slice are sorted using the given comparator function.</p>\n<p>Instead of using <code>PartialOrd::partial_cmp</code>, this function uses the given <code>compare</code>\nfunction to determine whether two elements are to be considered in sorted order.</p>\n<h5 id="examples-105"><a class="doc-anchor" href="#examples-105">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="macro">assert!</span>([<span class="number">1</span>, <span class="number">2</span>, <span class="number">2</span>, <span class="number">9</span>].is_sorted_by(|a, b| a &lt;= b));\n<span class="macro">assert!</span>(![<span class="number">1</span>, <span class="number">2</span>, <span class="number">2</span>, <span class="number">9</span>].is_sorted_by(|a, b| a &lt; b));\n\n<span class="macro">assert!</span>([<span class="number">0</span>].is_sorted_by(|a, b| <span class="bool-val">true</span>));\n<span class="macro">assert!</span>([<span class="number">0</span>].is_sorted_by(|a, b| <span class="bool-val">false</span>));\n\n<span class="kw">let </span>empty: [i32; <span class="number">0</span>] = [];\n<span class="macro">assert!</span>(empty.is_sorted_by(|a, b| <span class="bool-val">false</span>));\n<span class="macro">assert!</span>(empty.is_sorted_by(|a, b| <span class="bool-val">true</span>));</code></pre>'),
    ('is_sorted_by_key', '<p>Checks if the elements of this slice are sorted using the given key extraction function.</p>\n<p>Instead of comparing the slice’s elements directly, this function compares the keys of the\nelements, as determined by <code>f</code>. Apart from that, it’s equivalent to <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.is_sorted" title="method slice::is_sorted"><code>is_sorted</code></a>; see its\ndocumentation for more information.</p>\n<h5 id="examples-106"><a class="doc-anchor" href="#examples-106">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="macro">assert!</span>([<span class="string">"c"</span>, <span class="string">"bb"</span>, <span class="string">"aaa"</span>].is_sorted_by_key(|s| s.len()));\n<span class="macro">assert!</span>(![-<span class="number">2i32</span>, -<span class="number">1</span>, <span class="number">0</span>, <span class="number">3</span>].is_sorted_by_key(|n| n.abs()));</code></pre>'),
    ('partition_point', '<p>Returns the index of the partition point according to the given predicate\n(the index of the first element of the second partition).</p>\n<p>The slice is assumed to be partitioned according to the given predicate.\nThis means that all elements for which the predicate returns true are at the start of the slice\nand all elements for which the predicate returns false are at the end.\nFor example, <code>[7, 15, 3, 5, 4, 12, 6]</code> is partitioned under the predicate <code>x % 2 != 0</code>\n(all odd numbers are at the start, all even at the end).</p>\n<p>If this slice is not partitioned, the returned result is unspecified and meaningless,\nas this method performs a kind of binary search.</p>\n<p>See also <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.binary_search" title="method slice::binary_search"><code>binary_search</code></a>, <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.binary_search_by" title="method slice::binary_search_by"><code>binary_search_by</code></a>, and <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.binary_search_by_key" title="method slice::binary_search_by_key"><code>binary_search_by_key</code></a>.</p>\n<h5 id="examples-107"><a class="doc-anchor" href="#examples-107">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = [<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>, <span class="number">3</span>, <span class="number">5</span>, <span class="number">6</span>, <span class="number">7</span>];\n<span class="kw">let </span>i = v.partition_point(|<span class="kw-2">&amp;</span>x| x &lt; <span class="number">5</span>);\n\n<span class="macro">assert_eq!</span>(i, <span class="number">4</span>);\n<span class="macro">assert!</span>(v[..i].iter().all(|<span class="kw-2">&amp;</span>x| x &lt; <span class="number">5</span>));\n<span class="macro">assert!</span>(v[i..].iter().all(|<span class="kw-2">&amp;</span>x| !(x &lt; <span class="number">5</span>)));</code></pre>'),
    ('split_off', '<p>Removes the subslice corresponding to the given range\nand returns a reference to it.</p>\n<p>Returns <code>None</code> and does not modify the slice if the given\nrange is out of bounds.</p>\n<p>Note that this method only accepts one-sided ranges such as\n<code>2..</code> or <code>..6</code>, but not <code>2..6</code>.</p>\n<h5 id="examples-108"><a class="doc-anchor" href="#examples-108">§</a>Examples</h5>\n<p>Splitting off the first three elements of a slice:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>slice: <span class="kw-2">&amp;</span>[<span class="kw">_</span>] = <span class="kw-2">&amp;</span>[<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>, <span class="string">\'d\'</span>];\n<span class="kw">let </span><span class="kw-2">mut </span>first_three = slice.split_off(..<span class="number">3</span>).unwrap();\n\n<span class="macro">assert_eq!</span>(slice, <span class="kw-2">&amp;</span>[<span class="string">\'d\'</span>]);\n<span class="macro">assert_eq!</span>(first_three, <span class="kw-2">&amp;</span>[<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>]);</code></pre>'),
    ('split_off_mut', '<p>Removes the subslice corresponding to the given range\nand returns a mutable reference to it.</p>\n<p>Returns <code>None</code> and does not modify the slice if the given\nrange is out of bounds.</p>\n<p>Note that this method only accepts one-sided ranges such as\n<code>2..</code> or <code>..6</code>, but not <code>2..6</code>.</p>\n<h5 id="examples-109"><a class="doc-anchor" href="#examples-109">§</a>Examples</h5>\n<p>Splitting off the first three elements of a slice:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>slice: <span class="kw-2">&amp;mut </span>[<span class="kw">_</span>] = <span class="kw-2">&amp;mut </span>[<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>, <span class="string">\'d\'</span>];\n<span class="kw">let </span><span class="kw-2">mut </span>first_three = slice.split_off_mut(..<span class="number">3</span>).unwrap();\n\n<span class="macro">assert_eq!</span>(slice, <span class="kw-2">&amp;mut </span>[<span class="string">\'d\'</span>]);\n<span class="macro">assert_eq!</span>(first_three, <span class="kw-2">&amp;mut </span>[<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>]);</code></pre>'),
    ('split_off_first', '<p>Removes the first element of the slice and returns a reference\nto it.</p>\n<p>Returns <code>None</code> if the slice is empty.</p>\n<h5 id="examples-110"><a class="doc-anchor" href="#examples-110">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>slice: <span class="kw-2">&amp;</span>[<span class="kw">_</span>] = <span class="kw-2">&amp;</span>[<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>];\n<span class="kw">let </span>first = slice.split_off_first().unwrap();\n\n<span class="macro">assert_eq!</span>(slice, <span class="kw-2">&amp;</span>[<span class="string">\'b\'</span>, <span class="string">\'c\'</span>]);\n<span class="macro">assert_eq!</span>(first, <span class="kw-2">&amp;</span><span class="string">\'a\'</span>);</code></pre>'),
    ('split_off_first_mut', '<p>Removes the first element of the slice and returns a mutable\nreference to it.</p>\n<p>Returns <code>None</code> if the slice is empty.</p>\n<h5 id="examples-111"><a class="doc-anchor" href="#examples-111">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>slice: <span class="kw-2">&amp;mut </span>[<span class="kw">_</span>] = <span class="kw-2">&amp;mut </span>[<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>];\n<span class="kw">let </span>first = slice.split_off_first_mut().unwrap();\n<span class="kw-2">*</span>first = <span class="string">\'d\'</span>;\n\n<span class="macro">assert_eq!</span>(slice, <span class="kw-2">&amp;</span>[<span class="string">\'b\'</span>, <span class="string">\'c\'</span>]);\n<span class="macro">assert_eq!</span>(first, <span class="kw-2">&amp;</span><span class="string">\'d\'</span>);</code></pre>'),
    ('split_off_last', '<p>Removes the last element of the slice and returns a reference\nto it.</p>\n<p>Returns <code>None</code> if the slice is empty.</p>\n<h5 id="examples-112"><a class="doc-anchor" href="#examples-112">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>slice: <span class="kw-2">&amp;</span>[<span class="kw">_</span>] = <span class="kw-2">&amp;</span>[<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>];\n<span class="kw">let </span>last = slice.split_off_last().unwrap();\n\n<span class="macro">assert_eq!</span>(slice, <span class="kw-2">&amp;</span>[<span class="string">\'a\'</span>, <span class="string">\'b\'</span>]);\n<span class="macro">assert_eq!</span>(last, <span class="kw-2">&amp;</span><span class="string">\'c\'</span>);</code></pre>'),
    ('split_off_last_mut', '<p>Removes the last element of the slice and returns a mutable\nreference to it.</p>\n<p>Returns <code>None</code> if the slice is empty.</p>\n<h5 id="examples-113"><a class="doc-anchor" href="#examples-113">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>slice: <span class="kw-2">&amp;mut </span>[<span class="kw">_</span>] = <span class="kw-2">&amp;mut </span>[<span class="string">\'a\'</span>, <span class="string">\'b\'</span>, <span class="string">\'c\'</span>];\n<span class="kw">let </span>last = slice.split_off_last_mut().unwrap();\n<span class="kw-2">*</span>last = <span class="string">\'d\'</span>;\n\n<span class="macro">assert_eq!</span>(slice, <span class="kw-2">&amp;</span>[<span class="string">\'a\'</span>, <span class="string">\'b\'</span>]);\n<span class="macro">assert_eq!</span>(last, <span class="kw-2">&amp;</span><span class="string">\'d\'</span>);</code></pre>'),
    ('get_disjoint_unchecked_mut', '<p>Returns mutable references to many indices at once, without doing any checks.</p>\n<p>An index can be either a <code>usize</code>, a <a href="https://doc.rust-lang.org/1.95.0/core/ops/range/struct.Range.html" title="struct core::ops::range::Range"><code>Range</code></a> or a <a href="https://doc.rust-lang.org/1.95.0/core/ops/range/struct.RangeInclusive.html" title="struct core::ops::range::RangeInclusive"><code>RangeInclusive</code></a>. Note\nthat this method takes an array, so all indices must be of the same type.\nIf passed an array of <code>usize</code>s this method gives back an array of mutable references\nto single elements, while if passed an array of ranges it gives back an array of\nmutable references to slices.</p>\n<p>For a safe alternative see <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.get_disjoint_mut" title="method slice::get_disjoint_mut"><code>get_disjoint_mut</code></a>.</p>\n<h5 id="safety-10"><a class="doc-anchor" href="#safety-10">§</a>Safety</h5>\n<p>Calling this method with overlapping or out-of-bounds indices is <em><a href="https://doc.rust-lang.org/reference/behavior-considered-undefined.html">undefined behavior</a></em>\neven if the resulting references are not used.</p>\n<h5 id="examples-114"><a class="doc-anchor" href="#examples-114">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>x = <span class="kw-2">&amp;mut </span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>];\n\n<span class="kw">unsafe </span>{\n    <span class="kw">let </span>[a, b] = x.get_disjoint_unchecked_mut([<span class="number">0</span>, <span class="number">2</span>]);\n    <span class="kw-2">*</span>a <span class="kw-2">*</span>= <span class="number">10</span>;\n    <span class="kw-2">*</span>b <span class="kw-2">*</span>= <span class="number">100</span>;\n}\n<span class="macro">assert_eq!</span>(x, <span class="kw-2">&amp;</span>[<span class="number">10</span>, <span class="number">2</span>, <span class="number">400</span>]);\n\n<span class="kw">unsafe </span>{\n    <span class="kw">let </span>[a, b] = x.get_disjoint_unchecked_mut([<span class="number">0</span>..<span class="number">1</span>, <span class="number">1</span>..<span class="number">3</span>]);\n    a[<span class="number">0</span>] = <span class="number">8</span>;\n    b[<span class="number">0</span>] = <span class="number">88</span>;\n    b[<span class="number">1</span>] = <span class="number">888</span>;\n}\n<span class="macro">assert_eq!</span>(x, <span class="kw-2">&amp;</span>[<span class="number">8</span>, <span class="number">88</span>, <span class="number">888</span>]);\n\n<span class="kw">unsafe </span>{\n    <span class="kw">let </span>[a, b] = x.get_disjoint_unchecked_mut([<span class="number">1</span>..=<span class="number">2</span>, <span class="number">0</span>..=<span class="number">0</span>]);\n    a[<span class="number">0</span>] = <span class="number">11</span>;\n    a[<span class="number">1</span>] = <span class="number">111</span>;\n    b[<span class="number">0</span>] = <span class="number">1</span>;\n}\n<span class="macro">assert_eq!</span>(x, <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">11</span>, <span class="number">111</span>]);</code></pre>'),
    ('get_disjoint_mut', '<p>Returns mutable references to many indices at once.</p>\n<p>An index can be either a <code>usize</code>, a <a href="https://doc.rust-lang.org/1.95.0/core/ops/range/struct.Range.html" title="struct core::ops::range::Range"><code>Range</code></a> or a <a href="https://doc.rust-lang.org/1.95.0/core/ops/range/struct.RangeInclusive.html" title="struct core::ops::range::RangeInclusive"><code>RangeInclusive</code></a>. Note\nthat this method takes an array, so all indices must be of the same type.\nIf passed an array of <code>usize</code>s this method gives back an array of mutable references\nto single elements, while if passed an array of ranges it gives back an array of\nmutable references to slices.</p>\n<p>Returns an error if any index is out-of-bounds, or if there are overlapping indices.\nAn empty range is not considered to overlap if it is located at the beginning or at\nthe end of another range, but is considered to overlap if it is located in the middle.</p>\n<p>This method does a O(n^2) check to check that there are no overlapping indices, so be careful\nwhen passing many indices.</p>\n<h5 id="examples-115"><a class="doc-anchor" href="#examples-115">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>v = <span class="kw-2">&amp;mut </span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">3</span>];\n<span class="kw">if let </span><span class="prelude-val">Ok</span>([a, b]) = v.get_disjoint_mut([<span class="number">0</span>, <span class="number">2</span>]) {\n    <span class="kw-2">*</span>a = <span class="number">413</span>;\n    <span class="kw-2">*</span>b = <span class="number">612</span>;\n}\n<span class="macro">assert_eq!</span>(v, <span class="kw-2">&amp;</span>[<span class="number">413</span>, <span class="number">2</span>, <span class="number">612</span>]);\n\n<span class="kw">if let </span><span class="prelude-val">Ok</span>([a, b]) = v.get_disjoint_mut([<span class="number">0</span>..<span class="number">1</span>, <span class="number">1</span>..<span class="number">3</span>]) {\n    a[<span class="number">0</span>] = <span class="number">8</span>;\n    b[<span class="number">0</span>] = <span class="number">88</span>;\n    b[<span class="number">1</span>] = <span class="number">888</span>;\n}\n<span class="macro">assert_eq!</span>(v, <span class="kw-2">&amp;</span>[<span class="number">8</span>, <span class="number">88</span>, <span class="number">888</span>]);\n\n<span class="kw">if let </span><span class="prelude-val">Ok</span>([a, b]) = v.get_disjoint_mut([<span class="number">1</span>..=<span class="number">2</span>, <span class="number">0</span>..=<span class="number">0</span>]) {\n    a[<span class="number">0</span>] = <span class="number">11</span>;\n    a[<span class="number">1</span>] = <span class="number">111</span>;\n    b[<span class="number">0</span>] = <span class="number">1</span>;\n}\n<span class="macro">assert_eq!</span>(v, <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">11</span>, <span class="number">111</span>]);</code></pre>'),
    ('element_offset', '<p>Returns the index that an element reference points to.</p>\n<p>Returns <code>None</code> if <code>element</code> does not point to the start of an element within the slice.</p>\n<p>This method is useful for extending slice iterators like <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.split" title="method slice::split"><code>slice::split</code></a>.</p>\n<p>Note that this uses pointer arithmetic and <strong>does not compare elements</strong>.\nTo find the index of an element via comparison, use\n<a href="https://doc.rust-lang.org/1.95.0/core/iter/traits/iterator/trait.Iterator.html#method.position" title="method core::iter::traits::iterator::Iterator::position"><code>.iter().position()</code></a> instead.</p>\n<h5 id="panics-34"><a class="doc-anchor" href="#panics-34">§</a>Panics</h5>\n<p>Panics if <code>T</code> is zero-sized.</p>\n<h5 id="examples-116"><a class="doc-anchor" href="#examples-116">§</a>Examples</h5>\n<p>Basic usage:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span>nums: <span class="kw-2">&amp;</span>[u32] = <span class="kw-2">&amp;</span>[<span class="number">1</span>, <span class="number">7</span>, <span class="number">1</span>, <span class="number">1</span>];\n<span class="kw">let </span>num = <span class="kw-2">&amp;</span>nums[<span class="number">2</span>];\n\n<span class="macro">assert_eq!</span>(num, <span class="kw-2">&amp;</span><span class="number">1</span>);\n<span class="macro">assert_eq!</span>(nums.element_offset(num), <span class="prelude-val">Some</span>(<span class="number">2</span>));</code></pre>'),
    ('subslice_range', '<p>Returns the range of indices that a subslice points to.</p>\n<p>Returns <code>None</code> if <code>subslice</code> does not point within the slice or if it is not aligned with the\nelements in the slice.</p>\n<p>This method <strong>does not compare elements</strong>. Instead, this method finds the location in the slice that\n<code>subslice</code> was obtained from. To find the index of a subslice via comparison, instead use\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.windows" title="method slice::windows"><code>.windows()</code></a><a href="https://doc.rust-lang.org/1.95.0/core/iter/traits/iterator/trait.Iterator.html#method.position" title="method core::iter::traits::iterator::Iterator::position"><code>.position()</code></a>.</p>\n<p>This method is useful for extending slice iterators like <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.split" title="method slice::split"><code>slice::split</code></a>.</p>\n<p>Note that this may return a false positive (either <code>Some(0..0)</code> or <code>Some(self.len()..self.len())</code>)\nif <code>subslice</code> has a length of zero and points to the beginning or end of another, separate, slice.</p>\n<h5 id="panics-35"><a class="doc-anchor" href="#panics-35">§</a>Panics</h5>\n<p>Panics if <code>T</code> is zero-sized.</p>\n<h5 id="examples-117"><a class="doc-anchor" href="#examples-117">§</a>Examples</h5>\n<p>Basic usage:</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="attr">#![feature(substr_range)]\n\n</span><span class="kw">let </span>nums = <span class="kw-2">&amp;</span>[<span class="number">0</span>, <span class="number">5</span>, <span class="number">10</span>, <span class="number">0</span>, <span class="number">0</span>, <span class="number">5</span>];\n\n<span class="kw">let </span><span class="kw-2">mut </span>iter = nums\n    .split(|t| <span class="kw-2">*</span>t == <span class="number">0</span>)\n    .map(|n| nums.subslice_range(n).unwrap());\n\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">Some</span>(<span class="number">0</span>..<span class="number">0</span>));\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">Some</span>(<span class="number">1</span>..<span class="number">3</span>));\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">Some</span>(<span class="number">4</span>..<span class="number">4</span>));\n<span class="macro">assert_eq!</span>(iter.next(), <span class="prelude-val">Some</span>(<span class="number">5</span>..<span class="number">6</span>));</code></pre>'),
    ('utf8_chunks', '<p>Creates an iterator over the contiguous valid UTF-8 ranges of this\nslice, and the non-UTF-8 fragments in between.</p>\n<p>See the <a href="https://doc.rust-lang.org/1.95.0/core/str/lossy/struct.Utf8Chunk.html" title="struct core::str::lossy::Utf8Chunk"><code>Utf8Chunk</code></a> type for documentation of the items yielded by this iterator.</p>\n<h5 id="examples-118"><a class="doc-anchor" href="#examples-118">§</a>Examples</h5>\n<p>This function formats arbitrary but mostly-UTF-8 bytes into Rust source\ncode in the form of a C-string literal (<code>c"..."</code>).</p>\n\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">use </span>std::fmt::Write <span class="kw">as _</span>;\n\n<span class="kw">pub fn </span>cstr_literal(bytes: <span class="kw-2">&amp;</span>[u8]) -&gt; String {\n    <span class="kw">let </span><span class="kw-2">mut </span>repr = String::new();\n    repr.push_str(<span class="string">"c\\""</span>);\n    <span class="kw">for </span>chunk <span class="kw">in </span>bytes.utf8_chunks() {\n        <span class="kw">for </span>ch <span class="kw">in </span>chunk.valid().chars() {\n            <span class="comment">// Escapes \\0, \\t, \\r, \\n, \\\\, \\\', \\", and uses \\u{...} for non-printable characters.\n            </span><span class="macro">write!</span>(repr, <span class="string">"{}"</span>, ch.escape_debug()).unwrap();\n        }\n        <span class="kw">for </span>byte <span class="kw">in </span>chunk.invalid() {\n            <span class="macro">write!</span>(repr, <span class="string">"\\\\x{:02X}"</span>, byte).unwrap();\n        }\n    }\n    repr.push(<span class="string">\'"\'</span>);\n    repr\n}\n\n<span class="kw">fn </span>main() {\n    <span class="kw">let </span>lit = cstr_literal(<span class="string">b"\\xferris the \\xf0\\x9f\\xa6\\x80\\x07"</span>);\n    <span class="kw">let </span>expected = <span class="macro">stringify!</span>(<span class="string">c"\\xFErris the 🦀\\u{7}"</span>);\n    <span class="macro">assert_eq!</span>(lit, expected);\n}</code></pre>'),
    ('sort', '<p>Sorts the slice in ascending order, preserving initial order of equal elements.</p>\n<p>This sort is stable (i.e., does not reorder equal elements) and <em>O</em>(<em>n</em> * log(<em>n</em>))\nworst-case.</p>\n<p>If the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>T</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, the function\nmay panic; even if the function exits normally, the resulting order of elements in the slice\nis unspecified. See also the note on panicking below.</p>\n<p>When applicable, unstable sorting is preferred because it is generally faster than stable\nsorting and it doesn’t allocate auxiliary memory. See\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.sort_unstable" title="method slice::sort_unstable"><code>sort_unstable</code></a>. The exception are partially sorted slices, which\nmay be better served with <code>slice::sort</code>.</p>\n<p>Sorting types that only implement <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.PartialOrd.html" title="trait core::cmp::PartialOrd"><code>PartialOrd</code></a> such as <a href="https://doc.rust-lang.org/1.95.0/std/primitive.f32.html" title="primitive f32"><code>f32</code></a> and <a href="https://doc.rust-lang.org/1.95.0/std/primitive.f64.html" title="primitive f64"><code>f64</code></a> require\nadditional precautions. For example, <code>f32::NAN != f32::NAN</code>, which doesn’t fulfill the\nreflexivity requirement of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a>. By using an alternative comparison function with\n<code>slice::sort_by</code> such as <a href="https://doc.rust-lang.org/1.95.0/std/primitive.f32.html#method.total_cmp" title="method f32::total_cmp"><code>f32::total_cmp</code></a> or <a href="https://doc.rust-lang.org/1.95.0/std/primitive.f64.html#method.total_cmp" title="method f64::total_cmp"><code>f64::total_cmp</code></a> that defines a <a href="https://en.wikipedia.org/wiki/Total_order">total\norder</a> users can sort slices containing floating-point values. Alternatively, if all values\nin the slice are guaranteed to be in a subset for which <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.PartialOrd.html#tymethod.partial_cmp" title="method core::cmp::PartialOrd::partial_cmp"><code>PartialOrd::partial_cmp</code></a> forms a\n<a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, it’s possible to sort the slice with <code>sort_by(|a, b| a.partial_cmp(b).unwrap())</code>.</p>\n<h5 id="current-implementation-6"><a class="doc-anchor" href="#current-implementation-6">§</a>Current implementation</h5>\n<p>The current implementation is based on <a href="https://github.com/Voultapher/driftsort">driftsort</a> by Orson Peters and Lukas Bergdoll, which\ncombines the fast average case of quicksort with the fast worst case and partial run\ndetection of mergesort, achieving linear time on fully sorted and reversed inputs. On inputs\nwith k distinct elements, the expected time to sort the data is <em>O</em>(<em>n</em> * log(<em>k</em>)).</p>\n<p>The auxiliary memory allocation behavior depends on the input length. Short slices are\nhandled without allocation, medium sized slices allocate <code>self.len()</code> and beyond that it\nclamps at <code>self.len() / 2</code>.</p>\n<h5 id="panics-36"><a class="doc-anchor" href="#panics-36">§</a>Panics</h5>\n<p>May panic if the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>T</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, or if\nthe <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> implementation itself panics.</p>\n<p>All safe functions on slices preserve the invariant that even if the function panics, all\noriginal elements will remain in the slice and any possible modifications via interior\nmutability are observed in the input. This ensures that recovery code (for instance inside\nof a <code>Drop</code> or following a <code>catch_unwind</code>) will still have access to all the original\nelements. For instance, if the slice belongs to a <code>Vec</code>, the <code>Vec::drop</code> method will be able\nto dispose of all contained elements.</p>\n<h5 id="examples-119"><a class="doc-anchor" href="#examples-119">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">4</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>];\n\nv.sort();\n<span class="macro">assert_eq!</span>(v, [-<span class="number">5</span>, -<span class="number">3</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>]);</code></pre>'),
    ('sort_by', '<p>Sorts the slice in ascending order with a comparison function, preserving initial order of\nequal elements.</p>\n<p>This sort is stable (i.e., does not reorder equal elements) and <em>O</em>(<em>n</em> * log(<em>n</em>))\nworst-case.</p>\n<p>If the comparison function <code>compare</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, the function may\npanic; even if the function exits normally, the resulting order of elements in the slice is\nunspecified. See also the note on panicking below.</p>\n<p>For example <code>|a, b| (a - b).cmp(a)</code> is a comparison function that is neither transitive nor\nreflexive nor total, <code>a &lt; b &lt; c &lt; a</code> with <code>a = 1, b = 2, c = 3</code>. For more information and\nexamples see the <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> documentation.</p>\n<h5 id="current-implementation-7"><a class="doc-anchor" href="#current-implementation-7">§</a>Current implementation</h5>\n<p>The current implementation is based on <a href="https://github.com/Voultapher/driftsort">driftsort</a> by Orson Peters and Lukas Bergdoll, which\ncombines the fast average case of quicksort with the fast worst case and partial run\ndetection of mergesort, achieving linear time on fully sorted and reversed inputs. On inputs\nwith k distinct elements, the expected time to sort the data is <em>O</em>(<em>n</em> * log(<em>k</em>)).</p>\n<p>The auxiliary memory allocation behavior depends on the input length. Short slices are\nhandled without allocation, medium sized slices allocate <code>self.len()</code> and beyond that it\nclamps at <code>self.len() / 2</code>.</p>\n<h5 id="panics-37"><a class="doc-anchor" href="#panics-37">§</a>Panics</h5>\n<p>May panic if <code>compare</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, or if <code>compare</code> itself panics.</p>\n<p>All safe functions on slices preserve the invariant that even if the function panics, all\noriginal elements will remain in the slice and any possible modifications via interior\nmutability are observed in the input. This ensures that recovery code (for instance inside\nof a <code>Drop</code> or following a <code>catch_unwind</code>) will still have access to all the original\nelements. For instance, if the slice belongs to a <code>Vec</code>, the <code>Vec::drop</code> method will be able\nto dispose of all contained elements.</p>\n<h5 id="examples-120"><a class="doc-anchor" href="#examples-120">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">4</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>];\nv.sort_by(|a, b| a.cmp(b));\n<span class="macro">assert_eq!</span>(v, [-<span class="number">5</span>, -<span class="number">3</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">4</span>]);\n\n<span class="comment">// reverse sorting\n</span>v.sort_by(|a, b| b.cmp(a));\n<span class="macro">assert_eq!</span>(v, [<span class="number">4</span>, <span class="number">2</span>, <span class="number">1</span>, -<span class="number">3</span>, -<span class="number">5</span>]);</code></pre>'),
    ('sort_by_key', '<p>Sorts the slice in ascending order with a key extraction function, preserving initial order\nof equal elements.</p>\n<p>This sort is stable (i.e., does not reorder equal elements) and <em>O</em>(<em>m</em> * <em>n</em> * log(<em>n</em>))\nworst-case, where the key function is <em>O</em>(<em>m</em>).</p>\n<p>If the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>K</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, the function\nmay panic; even if the function exits normally, the resulting order of elements in the slice\nis unspecified. See also the note on panicking below.</p>\n<h5 id="current-implementation-8"><a class="doc-anchor" href="#current-implementation-8">§</a>Current implementation</h5>\n<p>The current implementation is based on <a href="https://github.com/Voultapher/driftsort">driftsort</a> by Orson Peters and Lukas Bergdoll, which\ncombines the fast average case of quicksort with the fast worst case and partial run\ndetection of mergesort, achieving linear time on fully sorted and reversed inputs. On inputs\nwith k distinct elements, the expected time to sort the data is <em>O</em>(<em>n</em> * log(<em>k</em>)).</p>\n<p>The auxiliary memory allocation behavior depends on the input length. Short slices are\nhandled without allocation, medium sized slices allocate <code>self.len()</code> and beyond that it\nclamps at <code>self.len() / 2</code>.</p>\n<h5 id="panics-38"><a class="doc-anchor" href="#panics-38">§</a>Panics</h5>\n<p>May panic if the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>K</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, or if\nthe <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> implementation or the key-function <code>f</code> panics.</p>\n<p>All safe functions on slices preserve the invariant that even if the function panics, all\noriginal elements will remain in the slice and any possible modifications via interior\nmutability are observed in the input. This ensures that recovery code (for instance inside\nof a <code>Drop</code> or following a <code>catch_unwind</code>) will still have access to all the original\nelements. For instance, if the slice belongs to a <code>Vec</code>, the <code>Vec::drop</code> method will be able\nto dispose of all contained elements.</p>\n<h5 id="examples-121"><a class="doc-anchor" href="#examples-121">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">4i32</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>];\n\nv.sort_by_key(|k| k.abs());\n<span class="macro">assert_eq!</span>(v, [<span class="number">1</span>, <span class="number">2</span>, -<span class="number">3</span>, <span class="number">4</span>, -<span class="number">5</span>]);</code></pre>'),
    ('sort_by_cached_key', '<p>Sorts the slice in ascending order with a key extraction function, preserving initial order\nof equal elements.</p>\n<p>This sort is stable (i.e., does not reorder equal elements) and <em>O</em>(<em>m</em> * <em>n</em> + <em>n</em> *\nlog(<em>n</em>)) worst-case, where the key function is <em>O</em>(<em>m</em>).</p>\n<p>During sorting, the key function is called at most once per element, by using temporary\nstorage to remember the results of key evaluation. The order of calls to the key function is\nunspecified and may change in future versions of the standard library.</p>\n<p>If the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>K</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, the function\nmay panic; even if the function exits normally, the resulting order of elements in the slice\nis unspecified. See also the note on panicking below.</p>\n<p>For simple key functions (e.g., functions that are property accesses or basic operations),\n<a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.sort_by_key" title="method slice::sort_by_key"><code>sort_by_key</code></a> is likely to be faster.</p>\n<h5 id="current-implementation-9"><a class="doc-anchor" href="#current-implementation-9">§</a>Current implementation</h5>\n<p>The current implementation is based on <a href="https://github.com/Voultapher/sort-research-rs/tree/main/ipnsort">instruction-parallel-network sort</a> by Lukas\nBergdoll, which combines the fast average case of randomized quicksort with the fast worst\ncase of heapsort, while achieving linear time on fully sorted and reversed inputs. And\n<em>O</em>(<em>k</em> * log(<em>n</em>)) where <em>k</em> is the number of distinct elements in the input. It leverages\nsuperscalar out-of-order execution capabilities commonly found in CPUs, to efficiently\nperform the operation.</p>\n<p>In the worst case, the algorithm allocates temporary storage in a <code>Vec&lt;(K, usize)&gt;</code> the\nlength of the slice.</p>\n<h5 id="panics-39"><a class="doc-anchor" href="#panics-39">§</a>Panics</h5>\n<p>May panic if the implementation of <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> for <code>K</code> does not implement a <a href="https://en.wikipedia.org/wiki/Total_order">total order</a>, or if\nthe <a href="https://doc.rust-lang.org/1.95.0/core/cmp/trait.Ord.html" title="trait core::cmp::Ord"><code>Ord</code></a> implementation panics.</p>\n<p>All safe functions on slices preserve the invariant that even if the function panics, all\noriginal elements will remain in the slice and any possible modifications via interior\nmutability are observed in the input. This ensures that recovery code (for instance inside\nof a <code>Drop</code> or following a <code>catch_unwind</code>) will still have access to all the original\nelements. For instance, if the slice belongs to a <code>Vec</code>, the <code>Vec::drop</code> method will be able\nto dispose of all contained elements.</p>\n<h5 id="examples-122"><a class="doc-anchor" href="#examples-122">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="kw">let </span><span class="kw-2">mut </span>v = [<span class="number">4i32</span>, -<span class="number">5</span>, <span class="number">1</span>, -<span class="number">3</span>, <span class="number">2</span>, <span class="number">10</span>];\n\n<span class="comment">// Strings are sorted by lexicographical order.\n</span>v.sort_by_cached_key(|k| k.to_string());\n<span class="macro">assert_eq!</span>(v, [-<span class="number">3</span>, -<span class="number">5</span>, <span class="number">1</span>, <span class="number">10</span>, <span class="number">2</span>, <span class="number">4</span>]);</code></pre>'),
    ('repeat', '<p>Creates a vector by copying a slice <code>n</code> times.</p>\n<h5 id="panics-40"><a class="doc-anchor" href="#panics-40">§</a>Panics</h5>\n<p>This function will panic if the capacity would overflow.</p>\n<h5 id="examples-125"><a class="doc-anchor" href="#examples-125">§</a>Examples</h5>\n<div class="example-wrap"><pre class="rust rust-example-rendered"><code><span class="macro">assert_eq!</span>([<span class="number">1</span>, <span class="number">2</span>].repeat(<span class="number">3</span>), <span class="macro">vec!</span>[<span class="number">1</span>, <span class="number">2</span>, <span class="number">1</span>, <span class="number">2</span>, <span class="number">1</span>, <span class="number">2</span>]);</code></pre>'),
    ('to_ascii_uppercase', '<p>Returns a vector containing a copy of this slice where each byte\nis mapped to its ASCII upper case equivalent.</p>\n<p>ASCII letters ‘a’ to ‘z’ are mapped to ‘A’ to ‘Z’,\nbut non-ASCII letters are unchanged.</p>\n<p>To uppercase the value in-place, use <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.make_ascii_uppercase" title="method slice::make_ascii_uppercase"><code>make_ascii_uppercase</code></a>.</p>\n'),
    ('to_ascii_lowercase', '<p>Returns a vector containing a copy of this slice where each byte\nis mapped to its ASCII lower case equivalent.</p>\n<p>ASCII letters ‘A’ to ‘Z’ are mapped to ‘a’ to ‘z’,\nbut non-ASCII letters are unchanged.</p>\n<p>To lowercase the value in-place, use <a href="https://doc.rust-lang.org/1.95.0/std/primitive.slice.html#method.make_ascii_lowercase" title="method slice::make_ascii_lowercase"><code>make_ascii_lowercase</code></a>.</p>\n'),
]
